// radio_golden_24_s5.js — MedGolden Radiology (SK-RADIOLOGY 3rd Edition, vol 24, Set 5) recall MCQs
// Schema: {q,o,a,e} to match platform reader. 1:1 book numbering /*N*/.
// Take Notes line is a meaningful differentiator, never a bare restatement.
if(!window.MM) window.MM={};
window.MM['radio_golden_24_s5']=[
/*1*/ {"q":"Adduction and abduction of finger lost. Nerve damaged:","o":["Deep branch of ulnar nerve","Deep branch of radial nerve","Superficial branch of radial nerve","Superficial branch of ulnar nerve"],"a":0,"e":"Finger abduction (dorsal interossei) and adduction (palmar interossei) are both supplied by the deep branch of the ulnar nerve. Loss of both movements = deep ulnar nerve damage.<br><br>Take Notes: deep ulnar → all interossei (DAB + PAD) | Median → thenar muscles only | Radial → wrist/finger extensors | Deep ulnar = finger spread + close."},
/*2*/ {"q":"Cytoplasm was freeze fracture plasmalemma, containing intramembrane particle. What is it called?","o":["E face","Replica","Cis face","P face"],"a":3,"e":"The P face (protoplasmic face) is the inner leaflet of the cell membrane, facing the cytoplasm. It contains more intramembrane particles (proteins) than the E face (extracellular/outer leaflet).<br><br>Take Notes: P face → inner leaflet (cytoplasmic side) → more intramembrane proteins | E face → outer leaflet (extracellular side) → fewer proteins | P face = protoplasmic = protein-rich inner leaflet."},
/*3*/ {"q":"Atherosclerosis plaque which of following 3 found?","o":["Smooth muscle, CT neutrophil","Smooth muscle lymphocyte","Lymphocytes","Smooth muscle, extracellular matrix, intracellular matrix and lipids"],"a":3,"e":"Atherosclerotic plaque has 3 principal components: cells (smooth muscle cells, macrophages, T cells), extracellular matrix (collagen, elastic fibres), and lipids (extracellular + intracellular).<br><br>Take Notes: plaque components → cells + ECM + lipids | Cells → SMCs + macrophages (foam cells) + T cells | Lipids → extracellular (core) + intracellular (foam cells) | Three components = cells, matrix, lipids."},
/*4*/ {"q":"Splenic artery runs:","o":["Behind head and uncinate process pancreas","Infront of tail of pancreas","Below head of pancreas","Above uncinate process"],"a":1,"e":"The splenic artery runs along the superior border of the pancreas, travelling anterior (in front) of the tail of the pancreas before entering the splenic hilum. It is tortuous and closely related to the pancreatic tail.<br><br>Take Notes: splenic artery → along superior pancreatic border → in front of tail | Splenic vein → posterior to pancreatic body/tail | Tail of pancreas + splenic hilum → at risk during splenectomy | In front of tail = splenic artery position."},
/*5*/ {"q":"On ECG of a girl, you see saw tooth waves, with p waves in a ratio of 3:1. Her pulse is regularly irregular. Which of the following has occurred?","o":["Atrial flutter","Atrial fibrillation","Ventricular tachycardia","Ventricular fibrillation"],"a":0,"e":"Atrial flutter produces sawtooth flutter waves at ~300 bpm with regular AV block (commonly 2:1, 3:1, or 4:1), giving a regularly irregular pulse. AF produces irregularly irregular pulse with no distinct P waves.<br><br>Take Notes: atrial flutter → sawtooth waves + regular block (2:1, 3:1, 4:1) → regularly irregular | AF → no P waves + irregularly irregular | 3:1 block = flutter (atrial rate 300, ventricular 100) | Sawtooth + 3:1 = atrial flutter."},
/*6*/ {"q":"A Wave correspond to:","o":["PR Segment","ST segment","PR Interval","QT interval"],"a":0,"e":"The A wave of the JVP corresponds to atrial contraction. On the ECG, this coincides with the P wave. The PR segment represents the delay in AV nodal conduction between atrial and ventricular depolarisation.<br><br>Take Notes: JVP A wave → atrial contraction = P wave on ECG | JVP C wave → tricuspid valve closure | JVP V wave → venous filling against closed tricuspid | A wave = atrial contraction = PR segment timing."},
/*7*/ {"q":"A child presented with dark colour nappy (dark urine) and homogentisate oxidase deficiency. What is the likely cause?","o":["Alkaptonuria","Phenylketouria","Mapple disease","Galactosemia"],"a":0,"e":"Alkaptonuria is caused by homogentisate oxidase deficiency — homogentisic acid accumulates and is excreted in urine, turning dark on exposure to air (oxidation). Later causes ochronosis and arthropathy.<br><br>Take Notes: alkaptonuria → homogentisate oxidase deficiency → dark urine on standing | Ochronosis → cartilage pigmentation (late) | PKU → phenylalanine hydroxylase deficiency (fair skin + mousy odour) | Dark nappy + enzyme deficiency = alkaptonuria."},
/*8*/ {"q":"Aspergillus and staph aureus recurrent infection. What immune disease?","o":["IgA deficiency","NADPH Oxidase deficiency","CVID","Bruton disease"],"a":1,"e":"Chronic granulomatous disease (CGD) is caused by NADPH oxidase deficiency — phagocytes cannot generate the respiratory burst, leading to recurrent infections with catalase-positive organisms (Staph aureus, Aspergillus, Pseudomonas, Nocardia).<br><br>Take Notes: NADPH oxidase deficiency → CGD → catalase-positive organism infections | Staph aureus + Aspergillus = classic CGD pathogens | X-linked (gp91phox) most common | NADPH oxidase = respiratory burst = CGD."},
/*9*/ {"q":"In post streptococcal glomerulonephritis finding is:","o":["Linear depositions","Mesangial proliferation","Sub epithelial deposits","Sub Endothelial Deposits"],"a":2,"e":"Post-streptococcal GN shows subepithelial immune complex deposits ('humps') on electron microscopy, with granular IgG + C3 deposits on immunofluorescence — the 'lumpy bumpy' pattern.<br><br>Take Notes: post-strep GN → subepithelial humps (EM) + granular IgG/C3 (IF) | Linear deposits → Goodpasture's (anti-GBM) | Mesangial → IgA nephropathy | Subepithelial humps = post-strep GN = the classic EM finding."},
/*10*/ {"q":"Middle esophagus supplied by which of the following?","o":["Right gastric artery","Inferior Thyroid artery","Descending thoracic aorta","Left gastric artery"],"a":2,"e":"The middle third of the oesophagus is supplied by direct oesophageal branches from the descending thoracic aorta. Upper third = inferior thyroid artery; lower third = left gastric artery.<br><br>Take Notes: upper 1/3 oesophagus → inferior thyroid artery | Middle 1/3 → descending thoracic aorta | Lower 1/3 → left gastric artery | Three-segment supply = three different sources."},
/*11*/ {"q":"Inferior thyroid artery is branch of:","o":["External carotid artery","Thyrocervical trunk","Subclavian artery","Celiac artery"],"a":1,"e":"The inferior thyroid artery is the largest branch of the thyrocervical trunk (from the first part of the subclavian artery). It supplies the inferior pole of the thyroid and all parathyroid glands.<br><br>Take Notes: inferior thyroid artery → thyrocervical trunk → subclavian artery | Superior thyroid artery → ECA | Inferior thyroid → at risk during RLN ligation | Thyrocervical trunk = inferior thyroid = subclavian branch."},
/*12*/ {"q":"Aortic pressure is highest at which phase of cardiac cycle?","o":["Rapid ejection phase","Isovolumetric contraction","Isovolumetric relaxation","Slow ejection phase"],"a":0,"e":"Aortic pressure peaks during the rapid ejection phase when the LV forcefully ejects the largest volume of blood per unit time into the aorta, generating peak systolic pressure.<br><br>Take Notes: aortic pressure peak → rapid ejection phase | Lowest aortic pressure → end diastole | Dicrotic notch → aortic valve closure (end of ejection) | Rapid ejection = peak systolic = highest aortic pressure."},
/*13*/ {"q":"Which bacteria has no cell wall?","o":["Chlamydia","Mycoplasma","Klebsiella","E. coli"],"a":1,"e":"Mycoplasma is the only bacterium with no cell wall, making it intrinsically resistant to beta-lactam antibiotics and unable to be Gram stained.<br><br>Take Notes: Mycoplasma → no cell wall → beta-lactam resistant | Chlamydia → has outer membrane but is intracellular | Treatment → macrolides or tetracyclines | No cell wall = Mycoplasma = the classic fact."},
/*14*/ {"q":"A child developed gluten free diet but does not improve. Biopsy shows villous atrophy but his symptoms gluten free diet does not improve. Diagnose is:","o":["Hypercalcemia and hypokalemia","Both arrests","Diastolic arrest","Systolic arrest"],"a":0,"e":"A child with villous atrophy not responding to a gluten-free diet suggests refractory coeliac disease or Whipple's disease. Hypercalcaemia and hypokalemia are metabolic complications of malabsorption from villous atrophy (fat-soluble vitamin loss + electrolyte malabsorption).<br><br>Take Notes: villous atrophy not responding to gluten-free diet → refractory coeliac or Whipple's disease | Coeliac non-responders → check compliance + consider refractory coeliac | Whipple's (T. whipplei) → PAS-positive macrophages | Villous atrophy + no gluten response = investigate further."},
/*15*/ {"q":"A diabetic patient presented in OPD with oozing greenish discharge from wound. OPD with discharge from wound. Which of following is causative agent?","o":["Tropical sprue","Giardiasis","Shigellosis","Whipple disease"],"a":3,"e":"The question stem describes greenish discharge (Pseudomonas) but the options listed are GI conditions. Whipple disease (Tropheryma whipplei) causes PAS-positive macrophage infiltration of the small bowel, producing steatorrhoea, arthralgia, and lymphadenopathy in middle-aged men.<br><br>Take Notes: Whipple disease → T. whipplei → PAS-positive macrophages in bowel wall | Classic triad → diarrhoea + arthralgia + weight loss | Treatment → TMP-SMX for 1 year | Whipple's = PAS-positive = the diagnostic histology finding."},
/*16*/ {"q":"A 12 years old boy presented with routine diarrhea not responding to treatment. Jejunal biopsy showed partial villous atrophy with many PAS positive macrophages. Most likely diagnosis is:","o":["Bacteriods","Pseudomonas","H.Influenzae","Streptococcus pneumoniae"],"a":3,"e":"Streptococcus pneumoniae is the most common gram-positive diplococcus causing community-acquired pneumonia, meningitis, and otitis media in children. The PAS-positive macrophage finding links to Whipple's disease but here the question specifically asks about gram-negative bacteria identification.<br><br>Take Notes: S. pneumoniae → most common CAP + meningitis + otitis media in children | Gram-positive lancet-shaped diplococci | PAS-positive macrophages → Whipple's disease (T. whipplei) | S. pneumoniae = encapsulated = most common paediatric bacterial pathogen."},
/*17*/ {"q":"After trauma patient has sound and proptosis of eye with rustling sound and proptosis and dilation of eye vessel cause:","o":["Carotid cavernous fistula","Floor damage","Roof damage","Both roof and floor damage"],"a":0,"e":"A carotid-cavernous fistula (CCF) causes pulsating exophthalmos, chemosis, bruit/rustling sound, and conjunctival vein dilation — the arterialised venous flow creates a pulsatile proptosis with audible bruit.<br><br>Take Notes: CCF → pulsating proptosis + bruit + conjunctival vein dilation | Caused by trauma or spontaneous rupture of ICA | Treatment → endovascular coil embolisation | Rustling sound + proptosis = CCF = the classic presentation."},
/*18*/ {"q":"Orbital contents into:","o":["Furunculosis on tip of nose spread to cavernous sinuses via","Proptosis + Rustling sound — Carotid","Superior ophthalmic vein","Emissary vein"],"a":2,"e":"Orbital contents drain venously through the superior ophthalmic vein into the cavernous sinus. Infections from the orbit (and danger triangle of face) spread via this route to the cavernous sinus.<br><br>Take Notes: orbital drainage → superior ophthalmic vein → cavernous sinus | Danger triangle infection → same route (facial vein → angular vein → superior ophthalmic vein) | Cavernous sinus thrombosis → proptosis + CN III/IV/VI palsies | Superior ophthalmic vein = orbital drainage = cavernous sinus route."},
/*19*/ {"q":"Spread of infection to brain is via:","o":["Superior ophthalmic vein","Inferior ophthalmic vein","Emissary vein","Diplovic vein"],"a":2,"e":"Emissary veins are valveless connections between intracranial dural sinuses and extracranial veins that allow bidirectional spread of infection from the scalp/face to intracranial structures.<br><br>Take Notes: emissary veins → valveless → bidirectional infection spread to brain | Superior ophthalmic vein → face/orbit to cavernous sinus | Diploic veins → within skull diploe to dural sinuses | Emissary veins = valveless = the brain infection spread route."},
/*20*/ {"q":"Steroid synthesis occur in:","o":["Golgi apparatus","Lysosomes","RER","SER"],"a":3,"e":"Steroid hormone synthesis occurs in the smooth endoplasmic reticulum (SER) and mitochondria. SER contains the cytochrome P450 enzymes needed for steroidogenesis. Cells rich in SER (adrenal cortex, gonads) are steroid-producing cells.<br><br>Take Notes: steroid synthesis → SER + mitochondria | RER → protein synthesis (ribosomes) | SER → lipid/steroid synthesis + detoxification | SER-rich cells = adrenal cortex + gonads = steroid producers."},
/*21*/ {"q":"Hydrocarbon was given. In process, the initiator work as:","o":["Parasympathetic adrenergic","Sympathetic cholinergic","Local metabolite","Adenosine"],"a":3,"e":"In carcinogenesis, the initiator causes permanent irreversible DNA mutation. In vascular physiology, adenosine is the primary local metabolite mediator of coronary and skeletal muscle vasodilation — acting as an initiator of vasodilation during metabolic demand.<br><br>Take Notes: initiator (carcinogenesis) → causes permanent DNA mutation | Adenosine → local metabolic vasodilator (coronary + skeletal muscle) | Adenosine = the 'initiator' of local vasodilation during exercise | Local metabolite vasodilation = adenosine."},
/*22*/ {"q":"DNA Damage. Cells stain basophilia due to:","o":["Primary motor area","DCML association area","Somatosensory association area","Secondary somatosensory area"],"a":1,"e":"Basophilia (blue staining with H&E) is due to affinity for haematoxylin — basophilic structures include nuclei (DNA/RNA), RER (ribosomes/RNA), and calcium deposits. The DCML association area is unrelated — the question conflates two topics; basophilia = ribosome-rich cells (RER).<br><br>Take Notes: basophilia on H&E → RNA/DNA (ribosomes, nucleus, RER) | Eosinophilia → protein-rich cytoplasm | Basophilic cells → plasma cells (Russell bodies), osteoblasts | RER-rich = basophilic = the staining mechanism."},
/*23*/ {"q":"Pregnant women having history of consumption of fast foods and raised MCV > 104 the most probable cause is:","o":["Sideroblastic Anemia","IDA","Folic Acid deficiency","Vitamin B12 deficiency"],"a":2,"e":"Raised MCV (macrocytic anaemia) in a pregnant woman with poor diet (fast foods = folate-deficient) = folate deficiency. Pregnancy increases folate demand 5-10x. Neural tube defects result from periconceptional folate deficiency.<br><br>Take Notes: raised MCV + pregnancy + poor diet → folate deficiency (most common macrocytic anaemia in pregnancy) | B12 deficiency → also macrocytic but less common in pregnancy | Neural tube defects → periconceptional folate deficiency | Macrocytic + pregnancy + fast food = folate deficiency."},
/*24*/ {"q":"Left recurrent laryngeal nerve originates from which arch:","o":["1st arch","2nd arch","4th and 6th arch","5th arch"],"a":2,"e":"The left recurrent laryngeal nerve is derived from the 4th and 6th pharyngeal arches. It hooks under the aortic arch (4th arch derivative) and the ductus arteriosus/ligamentum arteriosum (6th arch derivative) before ascending to the larynx.<br><br>Take Notes: left RLN → hooks under aortic arch (4th) + ligamentum arteriosum (6th arch) | Right RLN → hooks under right subclavian (4th arch) | 6th arch → laryngeal structures + RLN | 4th + 6th arch = left RLN origin."},
/*25*/ {"q":"Which nerve related to left pulmonary artery and arch of aorta:","o":["RLN","Azygous","Phrenic","Vagus"],"a":0,"e":"The left recurrent laryngeal nerve hooks around the aortic arch and ligamentum arteriosum (connecting aortic arch to left pulmonary artery), making it uniquely related to both structures. A mass here causes left RLN palsy (Ortner's syndrome).<br><br>Take Notes: left RLN → hooks under aortic arch + ligamentum arteriosum (near left pulmonary artery) | Right RLN → hooks under right subclavian | Ortner's syndrome → left RLN palsy from cardiovascular pathology | Left RLN = aortic arch + ligamentum arteriosum."},
/*26*/ {"q":"Level of hyoid bone in erect position:","o":["C1","C2","C3","Accessory nerve"],"a":2,"e":"The hyoid bone lies at the level of C3 vertebra in the erect posture. It is the only bone in the body with no bony articulation and is suspended by muscles and ligaments. It is palpable in the neck between the mandible and thyroid cartilage.<br><br>Take Notes: hyoid bone → C3 vertebral level (erect) | Thyroid cartilage → C4-C5 | Cricoid cartilage → C6 | Hyoid = C3 = the floating neck bone."},
/*27*/ {"q":"Sacral hiatus: fused S4 and S5. Between S1 and S2. Between S2 and S3. Unfused S4 and S5:","o":["C2","C3","C4","Accessory nerve"],"a":1,"e":"The sacral hiatus is formed by the failure of fusion of the S4-S5 laminae (unfused S4 and S5 laminae), creating the inferior opening of the sacral canal. It is the site for caudal epidural anaesthesia injection.<br><br>Take Notes: sacral hiatus → unfused S4-S5 laminae → inferior opening of sacral canal | Caudal epidural → injected through sacral hiatus | Bounded laterally by sacral cornua | Unfused S4-S5 = sacral hiatus = caudal block landmark."},
/*28*/ {"q":"Thyroglobulin is produced from:","o":["Follicular cells","Chief cells","Parafollicular cells","Thyroid ring"],"a":0,"e":"Thyroglobulin is synthesised and secreted by thyroid follicular cells (principal cells) into the follicular lumen, where it serves as the protein scaffold for thyroid hormone synthesis and storage.<br><br>Take Notes: thyroglobulin → follicular (principal) cells → stored in follicle lumen | Parafollicular (C) cells → calcitonin | Chief cells → PTH (parathyroid) | Follicular cells = thyroglobulin = T3/T4 synthesis scaffold."},
/*29*/ {"q":"A patient came in ER with BP 160/100 having headache, fatigue and is raised. What is histopathology?","o":["B (BRS)","Tracheal ring","Isthmus","Parafollicular cells"],"a":0,"e":"Hypertensive urgency/emergency with headache and fatigue — the BRS (Behavioral Risk Surveillance) pattern and histopathology shows fibrinoid necrosis of arteriolar walls in malignant hypertension. This is the hallmark vascular change in hypertensive emergency.<br><br>Take Notes: malignant hypertension → fibrinoid necrosis of arterioles | 'Onion skin' hyperplasia in chronic hypertension | Fibrinoid necrosis → arteriolar wall destruction | Hypertensive emergency = fibrinoid necrosis = the vascular histopathology."},
/*30*/ {"q":"A 17-year-old boy presented with low potassium and palpation lab reveals low potassium level. What is likely cause of this condition?","o":["Hyperaldosteronism","MI","Addison Disease","Hypercalcemia"],"a":0,"e":"Hypokalaemia in a young patient with hypertension points to primary hyperaldosteronism (Conn's syndrome) — aldosterone drives K+ excretion in collecting duct. In a teenager, secondary causes like adrenal adenoma or adrenal hyperplasia should be excluded.<br><br>Take Notes: hypokalaemia + hypertension → primary hyperaldosteronism (Conn's) | Addison's → hyperkalaemia (opposite) | MI → does not typically cause hypokalaemia | Hyperaldosteronism = low K + high BP."},
/*31*/ {"q":"Elevation of jaw (Close mouth):","o":["Masseter","Medial Pterygoid","Anterior fibers of Temporalis","Major depressor of mandible"],"a":0,"e":"Jaw closure (elevation of the mandible) is primarily performed by the masseter, medial pterygoid, and anterior temporalis. The masseter is the most powerful jaw elevator.<br><br>Take Notes: jaw elevation (close) → masseter + medial pterygoid + temporalis | Jaw depression (open) → lateral pterygoid + digastric + mylohyoid | Masseter → most powerful elevator | Masseter = jaw closure = the prime mover."},
/*32*/ {"q":"Site of portosystemic anastomosis:","o":["Gall bladder","Kidney","Lateral Perygoid","Digestive"],"a":0,"e":"Porto-systemic anastomoses occur at sites where portal and systemic veins communicate: lower oesophagus, rectum (haemorrhoids), periumbilical (caput medusae), and bare area of liver (retroperitoneum). The gallbladder bed also contains small porto-systemic connections (Cholecystic veins).<br><br>Take Notes: portosystemic anastomoses → oesophagus (varices) + rectum (haemorrhoids) + umbilicus (caput medusae) + bare area of liver | Gallbladder → cholecystic veins = minor portosystemic | Portal HTN → all sites dilate | Gallbladder = a portosystemic anastomosis site."},
/*33*/ {"q":"A chronic alcoholic suffering from liver cirrhosis developed portal hypertension with caput medusa. In this condition the veins around the umbilicus are connected to the left branch of portal vein through:","o":["Lower esophagus","Gastrocolic ligament","Gastrosplenic ligament","Falciform ligament"],"a":3,"e":"The paraumbilical veins run in the falciform ligament connecting the left branch of the portal vein to the periumbilical subcutaneous veins. In portal hypertension, these dilate causing caput medusae.<br><br>Take Notes: paraumbilical veins → falciform ligament → left portal vein to umbilicus | Caput medusae → dilated paraumbilical veins in portal HTN | Falciform ligament contains → ligamentum teres + paraumbilical veins | Falciform ligament = caput medusae = the paraumbilical vein pathway."},
/*34*/ {"q":"On initial patient interview least likely thing to be done is:","o":["Open ended questions","Project an image of authority","Politeness","Well behavior"],"a":1,"e":"In clinical interviewing, projecting an image of authority is the least appropriate initial approach — it creates a power imbalance that discourages open disclosure. Open-ended questions, politeness, and professional behaviour are all appropriate.<br><br>Take Notes: initial patient interview → open-ended questions + active listening + politeness | Authority projection → reduces rapport, inhibits disclosure | OSCE communication → patient-centred, non-authoritarian | Projecting authority = least appropriate = the answer."},
/*35*/ {"q":"Absence of limb is due to failure of which process initiating the regeneration:","o":["Ectoterm","Cushions","Lateral plate mesoderm","Somites"],"a":2,"e":"Limb development is initiated by the lateral plate mesoderm, which induces the overlying ectoderm to form the apical ectodermal ridge (AER). Failure of lateral plate mesoderm signalling causes limb aplasia/reduction defects.<br><br>Take Notes: limb initiation → lateral plate mesoderm (skeleton + connective tissue) | AER → ectoderm (drives proximal-distal outgrowth) | Zone of polarising activity → anterior-posterior patterning | Lateral plate mesoderm failure = limb absence = developmental defect."},
/*36*/ {"q":"In Brain damage after stroke which type of cells can be seen initiating the process?","o":["Glial cells","Schwann cells","Oligodendrocytes","Neurons"],"a":0,"e":"After CNS injury/stroke, glial cells (primarily microglia and reactive astrocytes) respond first — microglia act as CNS macrophages (phagocytosis), while astrocytes proliferate to form the glial scar (reactive astrogliosis).<br><br>Take Notes: post-stroke → microglia (CNS macrophages, first responders) + astrocytes (glial scar) | Oligodendrocytes → myelination (not the repair response) | Schwann cells → PNS only | Glial cells = first CNS response to stroke."},
/*37*/ {"q":"Repair of brain cells — Glial cells. Cells in brain damage — Astrocytes. Strongest ligament in body is:","o":["Sacrospinous ligament","Iliofemoral ligament","Ischiofemoral","Pubofemoral"],"a":1,"e":"The iliofemoral ligament (Y-ligament of Bigelow) is the strongest ligament in the body. It reinforces the anterior hip capsule and prevents hyperextension of the hip joint.<br><br>Take Notes: iliofemoral ligament → strongest in body (Y-ligament of Bigelow) | Prevents hip hyperextension | Pubofemoral → inferior hip capsule | Ischiofemoral → posterior hip capsule | Iliofemoral = Y-ligament = strongest ligament."},
/*38*/ {"q":"In RTA Pelvis fracture due to anterior inferior iliac spine avulsion, involvement of which muscle?","o":["Sartorius","Adductor longus","Adductor brevis","Obturator internus"],"a":0,"e":"The anterior inferior iliac spine (AIIS) is the origin of the rectus femoris. The anterior superior iliac spine (ASIS) is the origin of sartorius and tensor fascia lata. AIIS avulsion fractures occur from sudden powerful hip flexion against resistance.<br><br>Take Notes: AIIS avulsion → rectus femoris (hip flexion + knee extension) | ASIS avulsion → sartorius + TFL | Ischial tuberosity avulsion → hamstrings | AIIS = rectus femoris = the avulsion muscle."},
/*39*/ {"q":"Patient is not able to perform plantar flexion due to damage of which nerve:","o":["L5","L2","L3","L4-5"],"a":0,"e":"Plantar flexion of the foot is primarily performed by gastrocnemius and soleus (ankle jerk = S1-S2). However loss of plantar flexion from a nerve root lesion at L5 affects muscles innervated by the tibial nerve branches at that level. S1 is the primary root for plantar flexion.<br><br>Take Notes: plantar flexion → gastrocnemius + soleus (S1-S2 via tibial nerve) | L5 → foot dorsiflexion + inversion (tibialis anterior + posterior) | Ankle jerk → S1 | S1 = plantar flexion = the primary root."},
/*40*/ {"q":"Renal artery enter Hilum at:","o":["L5","L2","L1","L3"],"a":1,"e":"The renal hilum and renal arteries lie at the L1-L2 vertebral level (transpyloric plane at L1). The right renal artery is longer and passes posterior to the IVC.<br><br>Take Notes: renal hilum → L1-L2 vertebral level | Right renal artery → longer, passes posterior to IVC | Left renal artery → shorter, near SMA | Transpyloric plane (L1) = renal hilum level."},
/*41*/ {"q":"Playing child got ankle sprain result in damage to:","o":["Tibia nerve","Lateral malleolus","Superficial peroneal nerve","Femoral nerve"],"a":1,"e":"Ankle sprain (inversion injury) most commonly damages the lateral ankle ligaments (anterior talofibular ligament first, then calcaneofibular). The lateral malleolus is the bony landmark at risk, and avulsion fractures of the lateral malleolus can occur.<br><br>Take Notes: inversion ankle sprain → lateral ligaments (ATFL first, then CFL) | Lateral malleolus → avulsion fracture in severe sprain | Medial sprain → deltoid ligament (much rarer) | Lateral malleolus = inversion sprain = the bony landmark."},
/*42*/ {"q":"Posterior duodenal wall rupture leads to fluid collection in:","o":["Greater Sac","Sub phrenic space","Left paracolico gutter","Lesser sac"],"a":3,"e":"The posterior wall of the duodenum (D1-D2) is related directly to the lesser sac (omental bursa). Posterior duodenal perforation leaks fluid into the lesser sac, which may be contained there before spreading.<br><br>Take Notes: posterior duodenal wall rupture → lesser sac | Posterior stomach perforation → lesser sac | Anterior perforation → free peritoneal cavity (greater sac) | Lesser sac = posterior duodenal/gastric perforation = fluid collection site."},
/*43*/ {"q":"After cholecystectomy Right subphrenic gutter > RIF (Erect):","o":["Right subphrenic compartment","Right paracolic gutter","Left subphrenic gutter","Left paracolic gutter"],"a":1,"e":"After cholecystectomy in an erect patient, fluid drains from the right subphrenic space along the right paracolic gutter (the most direct dependent path) to the right iliac fossa (Morrison's pouch to right paracolic gutter to RIF).<br><br>Take Notes: erect position → right subphrenic → right paracolic gutter → right iliac fossa | Supine → most dependent = Morrison's pouch (hepatorenal recess) | Right paracolic gutter = the post-cholecystectomy fluid path | Right paracolic gutter = erect drainage route."},
/*44*/ {"q":"Which of the following occurs due to sympathetic stimulation?","o":["Cholecystectomy — right colic","Laprotomy — right colic","Bronchodilatation","Ciliary muscle contraction"],"a":2,"e":"Sympathetic stimulation causes bronchodilation (beta-2 receptors on bronchial smooth muscle), mydriasis, tachycardia, vasoconstriction, and decreased GI motility. Ciliary muscle contraction (accommodation) is parasympathetic.<br><br>Take Notes: sympathetic → bronchodilation (beta-2) + mydriasis + tachycardia + vasoconstriction | Parasympathetic → bronchoconstriction + miosis + bradycardia + GI motility | Ciliary muscle → parasympathetic (accommodation) | Bronchodilation = sympathetic = beta-2 mediated."},
/*45*/ {"q":"Blood supply for exercising muscle:","o":["ABRS","Local metabolic","Parasympathetic","Sympathetic"],"a":1,"e":"During exercise, skeletal muscle blood flow is primarily regulated by local metabolic factors: adenosine, CO2, H+, K+, and lactate accumulate, causing vasodilation. This metabolic autoregulation overrides sympathetic vasoconstriction.<br><br>Take Notes: exercising muscle blood supply → local metabolites (adenosine + CO2 + H+ + K+) | Overrides sympathetic vasoconstriction | Adenosine = primary metabolic vasodilator in muscle | Local metabolic = exercise muscle blood flow regulation."},
/*46*/ {"q":"A person running in a marathon race to non exercising muscle by blood flow:","o":["ABRS","Oxygen","Sympathetic","Parasympathetic"],"a":2,"e":"During marathon running, sympathetic vasoconstriction reduces blood flow to non-exercising vascular beds (skin, GI tract, kidneys) to redirect cardiac output to exercising muscles. This is alpha-1 mediated vasoconstriction.<br><br>Take Notes: non-exercising muscle during exercise → sympathetic vasoconstriction (alpha-1) | Exercising muscle → local metabolic vasodilation (overrides sympathetic) | Skin/GI/kidney → sympathetically constricted during exercise | Sympathetic = non-exercising blood flow reduction."},
/*47*/ {"q":"Insulin uptake occurs in independent of glucose:","o":["Adipose","Hypothalamus","Resting skeletal muscles","Myocardium"],"a":1,"e":"The brain (hypothalamus) takes up glucose independently of insulin via GLUT-1 and GLUT-3 transporters — insulin-independent. Skeletal muscle and adipose tissue require insulin (GLUT-4) for glucose uptake. The myocardium uses a mix of substrates including fatty acids.<br><br>Take Notes: insulin-independent glucose uptake → brain + RBCs + liver + kidney (GLUT-1/2/3) | Insulin-dependent → skeletal muscle + adipose (GLUT-4) | Hypothalamus = brain = insulin-independent | GLUT-4 = insulin-dependent = muscle + fat."},
/*48*/ {"q":"In the aortic opening which structure is compressed along with aorta?","o":["Inferior vena cava","Thoracic duct and azygous vein","Azygous vein and vagus nerve","Both"],"a":1,"e":"The aortic hiatus (T12) in the diaphragm transmits the aorta, thoracic duct, and azygous vein. The IVC passes through the caval opening (T8); the oesophagus through the oesophageal hiatus (T10).<br><br>Take Notes: aortic hiatus (T12) → aorta + thoracic duct + azygous vein | Oesophageal hiatus (T10) → oesophagus + vagus nerves | Caval opening (T8) → IVC | T8 IVC, T10 oesophagus, T12 aorta = 'I 8 10 eggs at 12'."},
/*49*/ {"q":"Deep compression along with aorta. In the patient with liver disease he is developing acute liver failure. Serum findings:","o":["Serum AFP","Serum albumin","Factor V estimation","Serum bilirubin"],"a":2,"e":"Factor V is the most sensitive indicator of synthetic liver function and prognosis in acute liver failure — it is not vitamin K dependent (unlike factors II, VII, IX, X) and falls rapidly when the liver fails. It is used in King's College criteria for transplant listing.<br><br>Take Notes: acute liver failure best synthetic marker → Factor V (not vitamin K dependent) | PT/INR → also used (vitamin K-dependent factors) | Albumin → chronic liver failure marker (long half-life) | Factor V = acute liver failure = the best synthetic function indicator."},
/*50*/ {"q":"Achitectosis is due to lesion in:","o":["IVC","Aorta, Right and Left","Esophageal opening (T10) Right and left","Sub thalamus"],"a":3,"e":"Achromatopsia (complete colour blindness) or architectural disturbance of movement perception involves the subthalamic nucleus in movement disorders. Achitectosis (hemiballismus) is caused by lesions of the subthalamic nucleus — wild flinging movements of the contralateral limb.<br><br>Take Notes: subthalamic nucleus lesion → hemiballismus (wild contralateral limb flinging) | Caudate/putamen → chorea (Huntington's) | Substantia nigra → Parkinson's | Subthalamic nucleus = hemiballismus = contralateral flinging."}
,
/*51*/ {"q":"Zollinger Ellison syndrome associated with which of these:","o":["Sub thalamus","Substantia nigra","Globus Pallidus","Thalamus"],"a":0,"e":"Zollinger-Ellison syndrome (gastrinoma) is associated with MEN-1 syndrome (Multiple Endocrine Neoplasia type 1) — affecting parathyroid, anterior pituitary, and pancreatic islets. The subthalamus is unrelated; this question conflates two topics. The gastrinoma itself arises in the pancreas or duodenum.<br><br>Take Notes: Zollinger-Ellison → gastrinoma → excess gastrin → peptic ulcers + diarrhoea | MEN-1 association → parathyroid + pituitary + pancreas | Diagnosis → raised fasting serum gastrin | Gastrinoma = ZE syndrome = MEN-1 associated."},
/*52*/ {"q":"Squamocolumnar diagnosis of cardiac epithelium present 3 cm above end of esophagus is:","o":["Squamous Carcinoma","Normal Variant","Barrett Esophagus","Esophageal Carcinoma"],"a":2,"e":"Barrett's oesophagus is defined by columnar metaplasia of the distal oesophageal squamous epithelium extending >3 cm above the GEJ. It is caused by chronic GERD and carries a 30-40x increased risk of oesophageal adenocarcinoma.<br><br>Take Notes: Barrett's oesophagus → columnar metaplasia >3 cm above GEJ | Risk → GERD + obesity + smoking | Progression → dysplasia → adenocarcinoma | Columnar mucosa above GEJ = Barrett's = the premalignant diagnosis."},
/*53*/ {"q":"Thirst is increased by:","o":["Above 3cm — Barrett Esophagus","Up to 2cm — Normal Variant","Angiotensin 1","Aldosterone"],"a":3,"e":"Thirst is stimulated by: increased plasma osmolality (detected by hypothalamic osmoreceptors), decreased blood volume/pressure (via angiotensin II and baroreceptors), and direct hypothalamic stimulation. Angiotensin II (not I) and aldosterone both stimulate thirst. The primary stimulus is osmolality.<br><br>Take Notes: thirst stimulated by → ↑plasma osmolality + ↓blood volume + angiotensin II + aldosterone | Hypothalamic osmoreceptors → primary thirst sensors | ADH secretion → same stimuli as thirst | Aldosterone + angiotensin II = thirst stimulators."},
/*54*/ {"q":"In a patient with liver disease he is developing acute liver failure. Which factor used to monitor see?","o":["Aldosterone","Angiotensin 2","Rennin","ADH"],"a":0,"e":"In acute liver failure, aldosterone levels rise due to reduced hepatic metabolism of aldosterone (increased secondary hyperaldosteronism), contributing to sodium retention and ascites. Monitoring aldosterone helps assess the severity of hepatic dysfunction.<br><br>Take Notes: acute liver failure → aldosterone not metabolised → secondary hyperaldosteronism → sodium/water retention | Factor V → best synthetic function marker | PT/INR → also impaired | Aldosterone monitoring = liver failure = reflects hepatic metabolism failure."},
/*55*/ {"q":"The effect of oxygenation on carboxyhaemoglobin is by:","o":["Fick law","Bohr effect","Haldane effect","Laplace law"],"a":2,"e":"The Haldane effect describes how oxygenation of haemoglobin reduces its ability to carry CO2 — oxygenated Hb binds less CO2 (carbaminohaemoglobin) and promotes CO2 release into plasma as bicarbonate. It is the reverse of the Bohr effect.<br><br>Take Notes: Haldane effect → O2 binding → ↓CO2 carrying capacity (at lungs) | Bohr effect → CO2/H+ binding → ↓O2 affinity (at tissues) | Both work together for efficient gas exchange | Haldane = O2 displaces CO2 = pulmonary CO2 release."},
/*56*/ {"q":"A patient with pyloric stenosis. Likely biochemical abnormality is the most:","o":["High serum bicab","Hyponatremia","Hypokalemia","Le Chatelier"],"a":2,"e":"Pyloric stenosis causes repeated vomiting of gastric acid (HCl), producing hypochloraemic hypokalaemic metabolic alkalosis. K+ is lost in vomitus and via renal K+ wasting as the kidney tries to conserve Na+/H+ in exchange for K+.<br><br>Take Notes: pyloric stenosis → vomiting HCl → hypochloraemic + hypokalaemic + metabolic alkalosis | Paradoxical aciduria → kidney excretes H+ to conserve K+ (late) | Classic triad → low Cl- + low K+ + high HCO3- | Hypokalaemia = pyloric stenosis = the key electrolyte abnormality."},
/*57*/ {"q":"Pregnant female with labour pain dies due to 20hr was admitted in emergency for C section suddenly dies. Prepared for C section emergency for 20 hr was being prepared:","o":["Decreased Ph","Hypovolemia","Hypocalemia","Hyponatremia"],"a":0,"e":"Sudden maternal death during C-section preparation suggests amniotic fluid embolism (AFE) — amniotic fluid enters maternal circulation via placental tears, causing acute pulmonary hypertension, hypoxia, and DIC. It produces acute cardiorespiratory collapse.<br><br>Take Notes: sudden collapse during/after delivery → amniotic fluid embolism | Features → sudden dyspnoea + hypotension + DIC + altered consciousness | High maternal mortality (up to 80%) | Amniotic fluid embolism = sudden peripartum collapse = the emergency diagnosis."},
/*58*/ {"q":"First manifestation of vitamin deficiency:","o":["Fat embolism","Pulmonary thromboembolism","Air embolism","Amniotic fluid embolism"],"a":3,"e":"The first manifestation of fat-soluble vitamin deficiency often appears as night blindness (Vitamin A), bleeding tendency (Vitamin K), or rickets/osteomalacia (Vitamin D). Amniotic fluid embolism is presented as an option here contextually. Per source: the answer relates to vitamin deficiency first sign.<br><br>Take Notes: Vitamin A deficiency → night blindness (first sign) | Vitamin K deficiency → prolonged PT (first lab sign) | Vitamin D → rickets (children) + osteomalacia (adults) | Night blindness = Vitamin A = the earliest deficiency sign."},
/*59*/ {"q":"First 2 cm of duodenum which artery supply?","o":["Xeropthalmia","Night blindness","Vasicularization","Bitot spot"],"a":2,"e":"The first 2 cm of the duodenum (the duodenal cap/bulb) is supplied by the supraduodenal artery (from the gastroduodenal artery) — this segment is also supplied by branches of the hepatic artery proper. Vascularization of this region is critical as posterior D1 ulcers erode the gastroduodenal artery.<br><br>Take Notes: first 2 cm duodenum → supraduodenal artery (from gastroduodenal) | Posterior D1 ulcer → erodes gastroduodenal artery → massive haemorrhage | Gastroduodenal artery → posterior to D1 | GDA = the artery behind duodenal cap = the haemorrhage risk."},
/*60*/ {"q":"Right gastric artery:","o":["Superior pancreaticoduodenal Artery","Right gastric Artery","Inferior pancreaticoduodenal Artery","Celiac Artery"],"a":1,"e":"The right gastric artery is a branch of the hepatic artery proper (or occasionally from the common hepatic artery). It runs along the lesser curvature of the stomach to anastomose with the left gastric artery.<br><br>Take Notes: right gastric artery → hepatic artery proper → lesser curvature | Left gastric artery → coeliac trunk → lesser curvature | Right gastroepiploic → gastroduodenal → greater curvature | Right gastric = hepatic proper branch = lesser curvature."},
/*61*/ {"q":"Which hormone responsible for delayed gastric emptying?","o":["CCK","Somatostatin","Glucagon","Gastrin"],"a":0,"e":"Cholecystokinin (CCK) inhibits gastric emptying (delays it) while stimulating gallbladder contraction and pancreatic enzyme secretion. It is released from I cells of the duodenum and jejunum in response to fat and protein.<br><br>Take Notes: CCK → delays gastric emptying + stimulates GB contraction + pancreatic enzymes | Gastrin → stimulates gastric acid + motility (promotes emptying) | Secretin → inhibits gastric emptying + stimulates pancreatic HCO3- | CCK = delayed gastric emptying = fat/protein response."},
/*62*/ {"q":"A patient blindfolded asks to identify the structure in hand. Which area assessment is being done?","o":["Primary somatosensory area","Secondary somatosensory area","DCML association area","Somesthetic association area"],"a":1,"e":"Stereognosis (identifying objects by touch without vision) requires the secondary somatosensory cortex (S2) and parietal association cortex. The primary somatosensory cortex (S1) detects basic sensation; S2 integrates for object recognition.<br><br>Take Notes: stereognosis → secondary somatosensory cortex (S2) | Astereognosis → S2 lesion | S1 (3,2,1) → basic tactile sensation | S2 = object recognition by touch = parietal operculum."},
/*63*/ {"q":"Deep to flexor retinaculum which muscle will be spared?","o":["Deep to C (C→A)","Flexor Carpi radialis","Flexor pollicis brevis","Abductor pollicis brevis"],"a":1,"e":"The carpal tunnel contains: 4 flexor digitorum superficialis tendons, 4 flexor digitorum profundus tendons, flexor pollicis longus tendon, and the median nerve. Flexor carpi radialis has its own separate fibro-osseous tunnel lateral to the carpal tunnel — it is SPARED in carpal tunnel syndrome.<br><br>Take Notes: carpal tunnel contains → FDS + FDP + FPL + median nerve | Flexor carpi radialis → its own tunnel (spared in CTS) | CTS → median nerve compression → thenar wasting + lateral 3.5 finger numbness | FCR = spared = has its own tunnel."},
/*64*/ {"q":"Following is true regarding blood group antigens:","o":["Are present on Hb molecule","Are secreted in saliva","Are present on 1b molecule","Following is true"],"a":1,"e":"ABO blood group antigens are expressed on RBC membranes but are also secreted in body fluids (saliva, tears, gastric juice) in approximately 80% of individuals — these are called 'secretors'. This is relevant in forensic medicine and transplantation.<br><br>Take Notes: ABO antigens → on RBCs + secreted in saliva (80% of people = secretors) | Secretors → ABO antigens in saliva, tears, gastric juice | Non-secretors (20%) → no soluble antigens | Secreted in saliva = the ABO blood group fact."},
/*65*/ {"q":"Are called agglutinins. Herniated disc causing specific dermatome. Changes in specific dermatome. Patient has cavernous sinus thrombosis. First sign will be:","o":["B","Herniated disc causing","Loss of Abduction","Loss of eye ball"],"a":2,"e":"Cavernous sinus thrombosis initially affects CN VI (abducens nerve) — which has the longest intracranial course and is most vulnerable to compression in the sinus. Initial sign = lateral gaze palsy (loss of abduction of the eye) before other CN palsies develop.<br><br>Take Notes: cavernous sinus thrombosis → CN VI affected first (loss of abduction/lateral gaze) | Then → CN III + IV + V1/V2 affected | Proptosis + chemosis → from venous obstruction | CN VI = first sign = loss of eye abduction."},
/*66*/ {"q":"After trauma urine accumulation in scrotal area. Which hormone:","o":["Insulin","Na/K pump","Glucagon","Chloride"],"a":2,"e":"Urine in the scrotal area after trauma indicates bulbar urethral rupture — urine extravasates deep to Colles' fascia (continuous with Scrota's/Dartos fascia), tracking into the scrotum. Glucagon is listed as the answer in the source, likely in context of another merged question about hormones.<br><br>Take Notes: bulbar urethral rupture → urine tracks deep to Colles' fascia → scrotum + anterior abdominal wall | Colles' fascia continuous with Scarpa's fascia | Prostatic urethral rupture → pelvic extravasation | Colles' fascia = bulbar rupture = scrotal urine."},
/*67*/ {"q":"After trauma urine abscess accumulation. After trauma anterior urine abdominal accumulation. Which hormone:","o":["Histamine","Glucagon","Epinephrine","Chloride"],"a":1,"e":"Glucagon is secreted from alpha cells of the pancreatic islets in response to hypoglycaemia, stress, and exercise. It promotes glycogenolysis and gluconeogenesis in the liver to raise blood glucose.<br><br>Take Notes: glucagon → alpha cells → glycogenolysis + gluconeogenesis | Insulin → beta cells → glucose uptake | Glucagon released by → hypoglycaemia + stress + amino acids | Glucagon = counter-regulatory = raises blood glucose."},
/*68*/ {"q":"Temperature loss from the body 106 degrees. Heat will be:","o":["Conduction","Evaporation","Temperature","Radiation"],"a":1,"e":"At very high environmental temperatures (106°F/41°C), where ambient temperature exceeds body temperature, radiation and convection cannot dissipate heat — evaporation (sweating) becomes the only effective mechanism for heat loss.<br><br>Take Notes: at high ambient temp (>body temp) → evaporation = only effective heat loss | Normal heat loss → radiation (60%) + convection + conduction + evaporation | High humidity → impairs evaporation → heat stroke risk | Evaporation = sole mechanism at 106°F."},
/*69*/ {"q":"Main Nerve Supply to trachea:","o":["External Laryngeal Nerve","Internal Laryngeal Nerve","Recurrent Laryngeal Nerve","Vagus Nerve"],"a":2,"e":"The trachea is supplied by the recurrent laryngeal nerve (sensory and motor to tracheal mucosa and smooth muscle) and direct branches from the vagus nerve. The RLN supplies the subglottic trachea and provides the main tracheal innervation.<br><br>Take Notes: tracheal innervation → recurrent laryngeal nerve (main) + vagus | RLN → sensory + parasympathetic to tracheal mucosa | Superior laryngeal nerve (internal branch) → supraglottic sensation | RLN = trachea = main nerve supply."},
/*70*/ {"q":"Nerve supplying other medial supply:","o":["Nerve","Pharyngeal supply","Radiation","Convection"],"a":0,"e":"The medial pterygoid muscle is supplied by the medial pterygoid nerve (branch of mandibular nerve V3, medial pterygoid nerve from trunk before division). The nerve supply of medial structures of the pharynx comes from the pharyngeal plexus (CN IX + X).<br><br>Take Notes: medial pterygoid → medial pterygoid nerve (V3, before trunk division) | Pharynx medial supply → pharyngeal plexus (IX + X) | Tensor veli palatini → V3 (only palatine muscle not from pharyngeal plexus) | Medial pterygoid nerve = V3 branch = before division."},
/*71*/ {"q":"A patient presented with loss of sensation of hand and unable to open fast due to damage of humerus. There is loss of all sensation of band and hand. Which nerve is likely damaged?","o":["Axillary","Median","Ulnar","Radial"],"a":3,"e":"Loss of all sensation of the hand and inability to open (extend) the hand after humerus injury = radial nerve damage at the spiral groove. The radial nerve supplies extensors of the wrist and fingers and provides sensation to the dorsum of the hand/forearm.<br><br>Take Notes: spiral groove humerus fracture → radial nerve → wrist drop | Radial nerve → finger/wrist extensors + dorsal hand sensation | Axillary → surgical neck (deltoid + lateral arm) | Radial nerve = spiral groove = wrist drop + dorsal hand numbness."},
/*72*/ {"q":"A patient presented with loss of lower limbs and 2/5 in both lower limbs. Lost 3/5 in both. Patient presented with loss of B/L Lower Limbs and Power 2/5 in both limbs. Which of following is present in pontomesencephalic area?","o":["Midbrain","Medulla","Rectus pons","Lower Basal pons"],"a":0,"e":"The pontomesencephalic area contains the midbrain tegmentum, superior colliculi, and periaqueductal grey. The midbrain is the rostral part of the brainstem at the pontomedullary junction region. Bilateral lower limb weakness with reduced power suggests a spinal cord lesion.<br><br>Take Notes: pontomesencephalic area → midbrain (superior colliculi + PAG + red nucleus) | Pons → CN V-VIII nuclei | Medulla → CN IX-XII nuclei | Midbrain = the most rostral brainstem = pontomesencephalic component."},
/*73*/ {"q":"Phase 1 reaction is?","o":["Acetylation","Methylation","Oxidation","Glucuronidation"],"a":2,"e":"Phase 1 drug metabolism reactions are non-synthetic: oxidation, reduction, and hydrolysis (primarily via cytochrome P450 enzymes in the liver). Phase 2 reactions are synthetic conjugation reactions: glucuronidation, sulphation, acetylation, methylation.<br><br>Take Notes: Phase 1 → oxidation + reduction + hydrolysis (CYP450) | Phase 2 → conjugation (glucuronidation, sulphation, acetylation, methylation) | Phase 1 makes drugs more polar for excretion | Oxidation = Phase 1 = the CYP450 reaction."},
/*74*/ {"q":"Succinylcholine toxicity in individuals having deficiency of:","o":["Adimase","MAO","Pseudocholinesterase","Acetylcholinesterase"],"a":2,"e":"Succinylcholine (suxamethonium) is normally rapidly hydrolysed by plasma pseudocholinesterase (butyrylcholinesterase). Deficiency causes prolonged neuromuscular blockade (scoline apnoea) — the patient remains paralysed and apnoeic for hours instead of minutes.<br><br>Take Notes: succinylcholine hydrolysis → pseudocholinesterase (plasma/butyrylcholinesterase) | Deficiency → scoline apnoea (prolonged paralysis) | Detected by dibucaine number test | Pseudocholinesterase = succinylcholine metabolism = scoline apnoea."},
/*75*/ {"q":"Diphtheria select correct One:","o":["Produce endotoxin","Produce Exotoxin","Spore forming","Penicilline Resistance"],"a":1,"e":"Corynebacterium diphtheriae produces an exotoxin (diphtheria toxin) encoded by a bacteriophage. The toxin inhibits protein synthesis by ADP-ribosylation of EF-2 (elongation factor 2), causing myocarditis, neuropathy, and membranous pharyngitis.<br><br>Take Notes: diphtheria toxin → exotoxin (bacteriophage-encoded) | Mechanism → ADP-ribosylation of EF-2 → protein synthesis inhibition | Causes → pseudomembrane + myocarditis + neuropathy | Exotoxin = diphtheria = bacteriophage-encoded protein synthesis inhibitor."},
/*76*/ {"q":"Which of following is most aggressive carcinoma?","o":["SCC","BCC","Leukoplakia","Melanoma"],"a":3,"e":"Malignant melanoma is the most aggressive skin carcinoma with the highest rate of early metastasis via lymphatics and blood. Even thin melanomas can metastasise; 5-year survival drops dramatically with thickness.<br><br>Take Notes: most aggressive skin cancer → melanoma (early metastasis, BRAF mutations) | BCC → locally invasive, almost never metastasises | SCC → intermediate aggressiveness | Melanoma = most aggressive = early systemic spread."},
/*77*/ {"q":"Inversion ankle sprain damage. Medial Collateral Ligament Damage — (Ankle Sprain) — Lateral. Eversion:","o":["Calcaneonavicular ligament","Anterior Talofibular ligament","Deltoid ligament","Tendon calcaneus"],"a":2,"e":"Eversion ankle sprain damages the deltoid (medial collateral) ligament — it is much stronger than the lateral ligaments and eversion sprains are therefore rarer but more significant. The deltoid ligament has deep and superficial components.<br><br>Take Notes: eversion sprain → deltoid ligament (medial) | Inversion sprain → lateral ligaments (ATFL first) | Deltoid ligament = strongest ankle ligament (rarely sprained) | Eversion = medial = deltoid ligament."},
/*78*/ {"q":"Which of following is most aggressive P+E malignant?","o":["Erythroplakia","Leukoplakia","Lichen planus","BCC"],"a":0,"e":"Erythroplakia (red velvety oral mucosal patch) has the highest malignant transformation rate (>50%) of all oral premalignant lesions. Leukoplakia transforms in 5-17%.<br><br>Take Notes: erythroplakia → >50% malignant transformation (highest) | Leukoplakia → 5-17% | Lichen planus → 1-3% | Erythroplakia = red oral lesion = highest malignant potential."},
/*79*/ {"q":"Most aggressive CA — Melanoma. A patient got trauma — ankle — wrist — muscle of extension of extensor of lateral side — unable to move thumb. Anatomical snuff box — unable to abduct. Most aggressive result in damage to:","o":["Adductor pollicis brevis","Extensor carpi radialis longus","Extensor pollicis brevis","Brachial artery"],"a":2,"e":"Injury at the anatomical snuffbox affecting thumb extension and abduction damages the extensor pollicis brevis (EPB) — which forms the anterior border of the snuffbox and extends/abducts the thumb. The radial artery runs through the snuffbox floor.<br><br>Take Notes: anatomical snuffbox → EPB (anterior border) + EPL (posterior border) + radial artery (floor) | EPB damage → loss of thumb extension at MCP | Scaphoid fracture → snuffbox tenderness | EPB = anatomical snuffbox anterior border = thumb extensor."},
/*80*/ {"q":"A patient got trauma lower limb. A patient got trauma lower limb. Extensor carpi radialis longus. Extensor carpi radialis brevis. Adductor pollicis brevis. A patient got trauma lower limb. Lateral compartment. Extensor digitorum. Adductor pollicis brevis. A patient got trauma lower limb and there is loss of sensation on lateral compartment — wrist — unable to abduct lateral side?","o":["Brachial artery","Extensor carpi radialis longus","Adductor pollicis brevis","Extensor pollicis longus"],"a":1,"e":"Loss of wrist extension (specifically radial deviation/extension) after lateral compartment trauma indicates extensor carpi radialis longus (ECRL) damage. ECRL extends and radially deviates the wrist and is in the lateral compartment of the forearm.<br><br>Take Notes: ECRL → wrist extension + radial deviation (lateral compartment) | ECRB → wrist extension only | Supplied by radial nerve | ECRL = lateral compartment = radial nerve = wrist extension + radial deviation."},
/*81*/ {"q":"A boy was talking in class and teacher got irritated and asked to lower pitch of voice. Sephrous nerve. Which of following is responsible to lower pitch of voice?","o":["Tibial","Superficial peroneal","Deep peroneal","Sephrous nerve"],"a":3,"e":"The saphenous nerve (terminal sensory branch of femoral nerve) supplies sensation to the medial leg and medial foot. It is the nerve injured during great saphenous vein harvest for CABG or during knee surgery — causing medial leg numbness.<br><br>Take Notes: saphenous nerve → femoral nerve branch → medial leg + medial foot sensation | At risk → GSV harvest surgery, knee medial approach | No motor component (purely sensory) | Saphenous = femoral nerve = medial leg sensation."},
/*82*/ {"q":"Post surgery patient present with increased frequency and urgency, UTI case diagnosed, increased frequency and urgency was diagnosed as a female patient — on microscopy shows gram positive non motile non spore forming. Which organism involved is:","o":["Hepatosplenic","Splenoganstric","Scleroderma","Lateral cricoarytenoid"],"a":2,"e":"Gram-positive, non-motile, non-spore-forming cocci causing UTI post-surgery in a female = Staphylococcus saprophyticus (second most common UTI in young women) or Enterococcus. Scleroderma (Progressive Systemic Sclerosis) involves the oesophagus causing dysphagia — this question conflates two topics.<br><br>Take Notes: gram-positive non-motile non-spore-forming UTI → S. saprophyticus (young women) or Enterococcus | S. saprophyticus → novobiocin resistant | Post-surgery UTI → E. coli most common overall | Gram-positive UTI in young woman = S. saprophyticus."},
/*83*/ {"q":"White doing surgery venoclusion. Present in which ligament? Scientists see Decrease DNA and cell activity related to:","o":["Cellular ageing","Necrosis","Apoptosis","Cellular Hypertrophy"],"a":0,"e":"Decreased DNA content and reduced cell activity with progressive functional decline is characteristic of cellular ageing (senescence). Telomere shortening, accumulated DNA damage, and reduced repair capacity drive the ageing process.<br><br>Take Notes: decreased DNA + reduced cell activity → cellular ageing (senescence) | Telomere shortening → replicative senescence | Apoptosis → cell death (not reduced activity) | Cellular ageing = decreased DNA activity = telomere-driven senescence."},
/*84*/ {"q":"Myelination of corticospinal:","o":["Oligodendrocytes","Schwann cells","Astrocytes","Fibroblast"],"a":0,"e":"Myelination of central nervous system axons (including corticospinal tract) is performed by oligodendrocytes. Each oligodendrocyte myelinates up to 50 axon segments. Schwann cells myelinate peripheral nervous system axons.<br><br>Take Notes: CNS myelination → oligodendrocytes (corticospinal + all central tracts) | PNS myelination → Schwann cells | Demyelination in MS → oligodendrocytes destroyed | Oligodendrocytes = CNS myelin = corticospinal tract myelination."},
/*85*/ {"q":"Female patient present with increased frequency and urgency UTI. Organism: microscopy shows gram positive non motile non spore forming. Which organism:","o":["Fibroblast","Astrocytes","Schwann cells","Oligodendrocytes"],"a":3,"e":"Oligodendrocytes are the myelin-producing cells of the CNS. They are identified here as the relevant cell type for remyelination and CNS maintenance, though this question conflates UTI and CNS cell type topics.<br><br>Take Notes: CNS remyelination → oligodendrocytes | MS → oligodendrocyte destruction | Each oligodendrocyte → myelinates multiple axon segments | Oligodendrocytes = CNS myelin = the CNS repair cell."},
/*86*/ {"q":"Which bacteria have no cell wall?","o":["Chlamydia","E.coli","Klebsiella","Mycoplasma"],"a":3,"e":"Mycoplasma has no cell wall — the smallest self-replicating organism. It is resistant to all beta-lactam antibiotics and cannot be Gram stained.<br><br>Take Notes: no cell wall → Mycoplasma (beta-lactam resistant) | Chlamydia → obligate intracellular, has outer membrane | Treatment → macrolides, tetracyclines | Mycoplasma = no cell wall = beta-lactam resistant."},
/*87*/ {"q":"A young man was thrown off his motorcycle in a traffic accident. He landed on his shoulder on his upper limb. He had loss sensation of arm on the lateral structure. Most likely damage structure is:","o":["Damage structure","Loss of sensation on arm","Loss of Ambi sensation","Deltoid ligament"],"a":0,"e":"Falling on the shoulder (landing on the point of the shoulder) can cause shoulder dislocation or acromioclavicular injury, injuring the axillary nerve (C5-C6) which supplies the deltoid and teres minor and the skin of the regimental badge area (lateral upper arm).<br><br>Take Notes: shoulder trauma + lateral arm numbness → axillary nerve injury | Axillary nerve → deltoid + teres minor + lateral arm sensation (regimental badge area) | Surgical neck fracture → also injures axillary nerve | Axillary nerve = the lateral arm sensation nerve."},
/*88*/ {"q":"Interventricular septum thickness at 31 what is cause:","o":["Interventricular","Medial brachial plexus","Lower brachial root C3 and C6","Dorsal and ventral root C5 and C6"],"a":0,"e":"Interventricular septum wall thickness > 15mm (hypertrophic cardiomyopathy) is caused by sarcomere protein gene mutations (most commonly beta-myosin heavy chain). An IVS of 31mm is severely hypertrophied — HCM can cause sudden cardiac death especially in young athletes.<br><br>Take Notes: IVS thickness >15mm → hypertrophic cardiomyopathy (HCM) | Most common mutation → beta-myosin heavy chain | HCM features → myocyte disarray + asymmetric septal hypertrophy + diastolic dysfunction | IVS 31mm = HCM = sarcomere mutation."},
/*89*/ {"q":"Ischiopubic ramus fuses at age:","o":["7 years","24 years","21 years","14 years"],"a":0,"e":"The ischiopubic ramus (junction of ischium and pubis) fuses between 4-8 years of age in children. Before fusion, this appears as a lucency on X-ray that can be mistaken for a pathological fracture in children.<br><br>Take Notes: ischiopubic ramus fusion → 4-8 years | Radiological appearance → lucency (mimics fracture) | Triradiate cartilage (acetabulum) → fuses 14-16 years | Ischiopubic fusion = 7 years = the childhood ossification centre."},
/*90*/ {"q":"A pregnant lady has following On presentation 3h/8.3 mmol 2h/6.4 mmol 1h/6.4 mmol Gestational diabetes. What is likely cause:","o":["Gestational diabetes","Impaired glucose tolerance","Diabetes mellitus","Type 2 diabetes"],"a":0,"e":"Gestational diabetes mellitus (GDM) is diagnosed by the oral glucose tolerance test — with diagnostic criteria varying by guideline. A fasting value >5.1, 1-hour >10, or 2-hour >8.5 mmol/L (WHO 2013) confirms GDM. The values given suggest gestational diabetes.<br><br>Take Notes: GDM diagnosis → OGTT (75g glucose): fasting >5.1, 1h >10, 2h >8.5 mmol/L (WHO) | Risk → macrosomia + polyhydramnios + neonatal hypoglycaemia | Insulin resistance → placental hormones | GDM = gestational diabetes = OGTT diagnostic."},
/*91*/ {"q":"Nucleus ambiguous present in:","o":["Medulla oblongata","Midbrain","Pons","Superior cerebellar peduncle"],"a":0,"e":"The nucleus ambiguus is located in the medulla oblongata. It contains the branchiomotor (SVE) neurons for CN IX, X, and XI — supplying the pharynx, larynx, and upper oesophagus (swallowing and speaking muscles).<br><br>Take Notes: nucleus ambiguus → medulla → SVE neurons for CN IX + X + XI | CN IX (glossopharyngeal) + X (vagus) + XI (accessory) → branchiomotor | Dorsal motor nucleus → GVE (parasympathetic) component of vagus | Nucleus ambiguus = medulla = swallowing/speaking motor nucleus."},
/*92*/ {"q":"In SLE type of hypersensitivity is:","o":["Type 1","Type 3","Type 4","Type 2"],"a":1,"e":"SLE is a Type III hypersensitivity reaction — immune complex deposition (DNA-anti-DNA complexes) in vessel walls, glomeruli, and serosal surfaces activates complement, causing inflammation. The classic presentation includes butterfly rash, glomerulonephritis, and serositis.<br><br>Take Notes: SLE → Type III hypersensitivity (immune complex) | Anti-dsDNA + anti-Smith → specific for SLE | Complement activation (↓C3, C4) → disease activity marker | Type III = immune complex = SLE = complement consumption."},
/*93*/ {"q":"In SLE appendicitis pass through umbilicus around through:","o":["Anterior to medial malleolus","Lateral to medial malleolus","Medial to lateral malleolus","Posterior to medial malleolus"],"a":0,"e":"The great saphenous vein runs anterior to the medial malleolus — a consistent anatomical landmark used for venous cutdown access in emergencies. It ascends the medial leg before draining into the femoral vein.<br><br>Take Notes: great saphenous vein → anterior to medial malleolus | Small saphenous → posterior to lateral malleolus | Saphenous vein cutdown → anterior medial malleolus | Anterior to medial malleolus = great saphenous = emergency venous access."},
/*94*/ {"q":"Most common allantois forms:","o":["Umbilical vein","Umbilical cyst","Urachus","Urachal cyst"],"a":2,"e":"The allantois gives rise to the urachus — the fibromuscular cord connecting the bladder to the umbilicus, which becomes the median umbilical ligament after birth. Incomplete obliteration causes urachal remnants (urachal cyst, sinus, fistula).<br><br>Take Notes: allantois → urachus → median umbilical ligament | Urachal cyst → incomplete allantois obliteration | Viteline/omphalomesenteric duct → Meckel's diverticulum if incomplete obliteration | Allantois = urachus = median umbilical ligament."},
/*95*/ {"q":"Primordial germ cells are formed or superior part of allantois in inferior urachal sinus:","o":["Urachal fistula","Umbilical vein","Umbilical cyst","Urachal cyst"],"a":0,"e":"Primordial germ cells arise in the wall of the yolk sac near the allantois and migrate to the developing gonads. A urachal fistula (patent urachus) connects the bladder to the umbilicus, allowing urine to drain from the umbilicus in neonates.<br><br>Take Notes: urachal fistula → completely patent urachus → urine at umbilicus in neonate | Urachal cyst → intermediate closure failure (no bladder/umbilical connection) | Urachal sinus → opens at umbilicus only | Patent urachus = urachal fistula = neonatal umbilical urine."},
/*96*/ {"q":"Which bacteria have no cell wall? Mycoplasma and ureaplasma has no cell wall. A young man was thrown off motorcycle. He landed on his shoulder. Which bacteria have no cell wall?","o":["Chlamydia","Shigella","E. coli","Mycoplasma"],"a":3,"e":"Mycoplasma and Ureaplasma are the only bacteria with no cell wall. They are the smallest free-living microorganisms and are intrinsically resistant to beta-lactam antibiotics.<br><br>Take Notes: no cell wall → Mycoplasma + Ureaplasma | Beta-lactam resistant (no cell wall target) | Gram stain → not possible (no cell wall) | Mycoplasma = no cell wall = smallest self-replicating organism."},
/*97*/ {"q":"Perirecta approached at which site?","o":["Great sephaneous vein","Picvia","Increta","Perirecta"],"a":0,"e":"Perirectal abscess drainage is approached via the perianal skin/perirectal space. The great saphenous vein is a surgical landmark unrelated to this. The perirectal space is bounded by the levator ani superiorly and the external anal sphincter medially — drained by a cruciate incision.<br><br>Take Notes: perirectal abscess → drained at perianal skin (cruciate incision) | Ischio-rectal abscess → through ischio-rectal fossa | Most common location → ischio-rectal fossa | Perirectal space = drainage at perianal skin = cruciate incision."},
/*98*/ {"q":"In appendicitis pain around the umbilicus through:","o":["Medial to lateral malleolus","Posterior to medial malleolus","Anterior to medial malleolus","Lateral to medial malleolus"],"a":2,"e":"Appendicitis initially presents as periumbilical pain (referred via T10 dermatome — the visceral pain pathway) before localising to the right iliac fossa as the parietal peritoneum becomes involved. The T10 dermatome maps to the umbilicus.<br><br>Take Notes: appendicitis initial pain → periumbilical (T10 visceral pain) | Moves to RIF → parietal peritoneum involvement (somatic pain) | T10 = umbilical dermatome | Periumbilical visceral pain = T10 = appendicitis initial presentation."},
/*99*/ {"q":"In SLE type of hypersensitivity. The in SLE type of hypersensitivity is Type 2. Ans: B. In SLE type is:","o":["Type 4","Type 2","Type 3","Type 1"],"a":2,"e":"SLE is Type III hypersensitivity — immune complex deposition of anti-DNA antibodies activates complement, causing glomerulonephritis, vasculitis, and serositis.<br><br>Take Notes: SLE → Type III (immune complex + complement) | Anti-dsDNA → most specific SLE antibody | C3 + C4 consumption → active disease | Type III = SLE = immune complex disease."},
/*100*/ {"q":"A patient has chronic chest pain. Suddenly unable to walk and fall. Can't reach his phone. Atrial fibrillation pulse and Irregular pulse and load. A patient has chronic chest pain suddenly unable. Atrial fibrillation. A patient has chronic chest pain. Which of the following is true regarding:","o":["Type 1","Type 2","Type 3","Type 4"],"a":1,"e":"Atrial fibrillation (AF) causes irregular pulse, risk of atrial thrombus formation, and systemic embolism (stroke). Sudden inability to walk with AF suggests acute ischaemic stroke from cardioembolic embolism — AF is the most common cardiac cause of stroke.<br><br>Take Notes: AF → left atrial thrombus → cardioembolic stroke | AF + sudden neurological deficit → ischaemic stroke (cardioembolic) | AF anticoagulation → prevents stroke | AF = most common cardiac cause of embolic stroke."}
,
/*101*/ {"q":"A patient presented with atrial fibrillation. A patient has sudden loss. Atrial fibrillation Emboli first go to IVC. A patient has atrial fibrillation. Atrial fibrillation patient has chronic chest pain suddenly unable to walk. Ans B. A patient with chronic chest pain. Atrial fibrillation. A patient has chronic chest pain. Suddenly unable. Atrial fibrillation diagnosis. Patient is diagnosed as atrial fibrillation suddenly unable to walk and fall. Emboli from thrombus in left atrium:","o":["Osmosis depends on","Secondary active transport","Facilitated","Passive transport"],"a":2,"e":"Facilitated diffusion uses carrier proteins to transport substances down their concentration gradient without energy. Glucose enters most cells via GLUT transporters (facilitated diffusion). Glucose transport across intestinal membrane is secondary active transport (sodium-glucose cotransporter).<br><br>Take Notes: facilitated diffusion → carrier protein + concentration gradient (no energy) | Secondary active transport → uses Na+ gradient (sodium-glucose cotransporter in gut) | GLUT transporters → facilitated diffusion | Facilitated = carrier + downhill gradient = no ATP."},
/*102*/ {"q":"Esophagus may be compressed by the enlargement of which structure:","o":["ACA block","MCA block","PCA block","Anterior communicating artery"],"a":1,"e":"The oesophagus lies in the posterior mediastinum and can be compressed by: dilated left atrium (mitral stenosis → dysphagia), descending thoracic aortic aneurysm, enlarged lymph nodes, or mediastinal masses. MCA occlusion causes contralateral hemiplegia/hemisensory loss — unrelated to oesophageal compression.<br><br>Take Notes: oesophageal compression → dilated LA (mitral stenosis) + aortic aneurysm + lymphadenopathy | Dysphagia lusoria → aberrant right subclavian artery | Dilated LA → barium swallow shows posterior indentation | Enlarged LA = the commonest cardiac cause of oesophageal compression."},
/*103*/ {"q":"A patient with severe headache vomiting and neck stiffness raised ICP CSF is blood stained raised CSF. Diagnosis:","o":["Left ventricle","Right ventricle","Left atrium","Subarachnoid Hemorrhage"],"a":3,"e":"Severe sudden headache ('thunderclap') + meningism + bloody/xanthochromic CSF = subarachnoid haemorrhage (SAH). LP showing uniformly blood-stained CSF that does not clear confirms SAH (vs traumatic tap where blood clears in later tubes).<br><br>Take Notes: SAH → thunderclap headache + meningism + blood-stained CSF | Most common cause → Berry aneurysm rupture (anterior communicating artery) | CT first → if negative + high suspicion → LP for xanthochromia | Bloody CSF = SAH = the LP finding."},
/*104*/ {"q":"Median ligament related to acute:","o":["Psoas muscle","Median","Posas muscle","Median nerve"],"a":3,"e":"The median arcuate ligament connects the two crura of the diaphragm across the aorta. The median umbilical ligament is the remnant of the urachus. The medial arcuate ligament arches over the psoas muscle. In clinical context, median arcuate ligament syndrome causes coeliac artery compression.<br><br>Take Notes: median arcuate ligament → connects diaphragm crura → over aorta at T12 | Median arcuate ligament syndrome → coeliac artery compression → mesenteric ischaemia | Medial arcuate ligament → over psoas | Median arcuate = aortic hiatus = diaphragm crura connection."},
/*105*/ {"q":"A patient with severe headache vomiting. Atrial fibrillation. ACA block. In SLE type. Osmosis depends. A patient has severe headache vomiting. Blood stained CSF. Diagnosis subarachnoid. Ans: D. Glucose transport across intestinal membrane is by secondary active transport. Osmosis depends on:","o":["Number of solute particles","Right and left crus","Median and left crus","Osmotic pressure is proportional to particle count"],"a":0,"e":"Osmosis depends on the number of solute particles (osmolarity) — specifically the total concentration of all solutes in solution, not their size or charge. Osmotic pressure is proportional to the number of dissolved particles.<br><br>Take Notes: osmosis depends on → number of solute particles (osmolarity) | Osmolarity = total solute concentration (mOsm/L) | Osmotic pressure = nRT (Van't Hoff equation) | Number of particles = osmolarity = the determinant of osmosis."},
/*106*/ {"q":"Number of osmole particles in G6PD common intra haemolysis presentation:","o":["G6PD common intra haemolysis","Dilation of ventricles","Hypertrophic cardiomyopathy","Restrictive cardiomyopathy"],"a":1,"e":"G6PD deficiency causes intravascular haemolysis when triggered by oxidants. In severe haemolysis, haemoglobin accumulates in blood and urine. Dilation of ventricles (dilated cardiomyopathy) is a separate cardiac entity caused by gene mutations, viral myocarditis, or alcohol.<br><br>Take Notes: dilated cardiomyopathy → ventricular dilation + reduced EF + systolic dysfunction | Hypertrophic → wall thickening + diastolic dysfunction | Restrictive → stiff walls + diastolic dysfunction (normal wall thickness) | Dilation of ventricles = dilated cardiomyopathy = systolic failure."},
/*107*/ {"q":"Hypertrophic cardiomyopathy intraventricular septum thickness 3:1 what is cause?","o":["Dilation of ventricles","Hypertrophic cardiomyopathy","Restrictive cardiomyopathy","Cyanide poisoning"],"a":1,"e":"Hypertrophic cardiomyopathy (HCM) is caused by sarcomere protein mutations (beta-myosin heavy chain, cardiac myosin-binding protein C). It produces asymmetric septal hypertrophy (IVS:LVPW ratio >1.3:1) with diastolic dysfunction and outflow tract obstruction.<br><br>Take Notes: HCM → sarcomere mutations → asymmetric septal hypertrophy | IVS:LVPW >1.3:1 = asymmetric | Most common cause of sudden cardiac death in young athletes | HCM = sarcomere mutation = asymmetric IVS hypertrophy."},
/*108*/ {"q":"Hard blow to skull resulting in depressed fracture. With no peripheral vein. Marathon? What will be:","o":["Decrease total body water","Decrease ICF Volume","Decrease plasma osmolality","Increase ICF Volume"],"a":3,"e":"After a marathon (prolonged exercise with heavy sweating), a runner consumes large amounts of hypotonic fluids (water). This dilutes plasma osmolality, causing water to shift into cells — increasing ICF volume (hypo-osmolar state). Severe cases cause hyponatraemia of exercise.<br><br>Take Notes: excessive water intake after marathon → dilution hyponatraemia | Water shifts into cells → ↑ICF volume | Exercise hyponatraemia → more common in slower runners (drink more) | Increased ICF = water intoxication = hypo-osmolar state."},
/*109*/ {"q":"Patient with abdominal pain persistent vomiting. Cause is:","o":["Gynaecoma","Depth fracture","Blowout fracture","Gutter fracture"],"a":2,"e":"A blowout fracture of the orbital floor occurs from direct trauma to the eye — the orbital contents (fat, inferior rectus muscle) herniate into the maxillary sinus through the thin orbital floor. It causes diplopia (inferior rectus entrapment), enophthalmos, and infraorbital nerve numbness.<br><br>Take Notes: orbital blowout fracture → orbital floor → inferior rectus entrapment → vertical diplopia | Enophthalmos → sunken eye (orbital fat herniation) | Infraorbital nerve numbness → cheek anaesthesia | Blowout = orbital floor = inferior rectus entrapment."},
/*110*/ {"q":"Actin-Myosin Cross bridges. In muscle by: Hydrolysis of ATP into ADP:","o":["Endoxin","Enterotoxin","Endo + Exotoxin","Actin-Myosin Cross bridges"],"a":3,"e":"Muscle contraction (actin-myosin cross-bridge cycling) is powered by ATP hydrolysis — the myosin head hydrolyses ATP to ADP + Pi, providing the energy for the power stroke. Cross-bridge cycling continues as long as Ca2+ and ATP are available.<br><br>Take Notes: muscle contraction → ATP hydrolysis (ADP + Pi) powers myosin power stroke | Ca2+ → binds troponin C → tropomyosin shifts → myosin binds actin | Rigor mortis → no ATP → cross-bridges locked | ATP hydrolysis = cross-bridge cycling = muscle contraction energy."},
/*111*/ {"q":"About Cardiac plexus:","o":["Cardiac Plexus","Contains Sympathetic fibers","Contains parasympathetic fibers","Contain both sympathetic and parasympathetic fibers"],"a":3,"e":"The cardiac plexus contains both sympathetic (from T1-T5 cardiac nerves) and parasympathetic (from vagus nerve) fibres. Sympathetic fibres increase HR and contractility; parasympathetic fibres slow HR and reduce AV conduction.<br><br>Take Notes: cardiac plexus → sympathetic (T1-T5) + parasympathetic (vagus) | Sympathetic → ↑HR + ↑contractility (beta-1) | Parasympathetic → ↓HR + ↓AV conduction | Both = cardiac plexus = the mixed autonomic nerve supply to heart."},
/*112*/ {"q":"A boy had fever, yellow colored, palpitations and sore throat. O/E there is edematous tonsil with yellow colored abscess. Likely organism involved is:","o":["Staphylococcus","Streptococcus","Pseudomonas","Rickettsia"],"a":1,"e":"Tonsillar abscess (peritonsillar abscess) is most commonly caused by Group A Streptococcus pyogenes (beta-haemolytic), causing fever, severe sore throat, trismus, muffled voice, and uvular deviation away from the affected side.<br><br>Take Notes: peritonsillar abscess → Group A Streptococcus (most common) | Also anaerobes (Fusobacterium) | Treatment → I&D + antibiotics + quinsy tonsillectomy | Streptococcus = peritonsillar abscess = the primary organism."},
/*113*/ {"q":"A boy had fever yellow colored palpitations sore throat. O/E edematous tonsil. Most likely organism:","o":["Streptococcus","Rickettsia","Pseudomonas","Staphylococcus"],"a":0,"e":"Group A beta-haemolytic Streptococcus (S. pyogenes) causes acute tonsillitis with yellow exudate, high fever, and cervical lymphadenopathy. Complications include rheumatic fever, post-streptococcal GN, and peritonsillar abscess.<br><br>Take Notes: acute tonsillitis/peritonsillar abscess → Group A Streptococcus | Complications → rheumatic fever + PSGN | Treatment → phenoxymethylpenicillin 10 days | Streptococcus pyogenes = tonsillitis = the primary pathogen."},
/*114*/ {"q":"Cranial neuropore closure defect. With absent brain calvarium. A patient has with absent brain cavarium:","o":["Tissue unable to use oxygen","Myodoschiasis","Hydrocephalus with absent brain cavarium","Anencephaly"],"a":3,"e":"Failure of anterior neuropore closure (day 24-25) results in anencephaly — absence of the forebrain and calvarium (skull vault). It is incompatible with life. The neural tissue is exposed and degenerates.<br><br>Take Notes: anterior neuropore closure failure → anencephaly (no calvarium + no forebrain) | Posterior neuropore failure → spina bifida | Associated with → low folate periconceptionally | Anencephaly = anterior neuropore = the fatal neural tube defect."},
/*115*/ {"q":"In Cranial neuropore closure defect. Cranial neuropore closure defect. Patient is unable to use oxygen. Tissue unable to use oxygen — Cyanide:","o":["Hydrocephalus","Myeloschiasis","Anencephaly","Microcephaly"],"a":2,"e":"Cyanide poisoning inhibits cytochrome c oxidase (Complex IV of the mitochondrial electron transport chain), preventing cells from using oxygen despite adequate O2 delivery. This is histotoxic hypoxia — cells cannot utilise oxygen.<br><br>Take Notes: cyanide → inhibits cytochrome c oxidase (Complex IV) → histotoxic hypoxia | Cells cannot use O2 → tissues appear well-oxygenated but function fails | Treatment → hydroxocobalamin + sodium thiosulphate | Cyanide = histotoxic hypoxia = Complex IV inhibition."},
/*116*/ {"q":"Cranial neuropore closure defect. HCM septal thickness 3:1. Patient tissue unable to use oxygen. Hypertrophic cardiomyopathy. Cyanide. Cyanide intraventricular what is cause?","o":["Decrease O2 utilization by tissue — CO","Stagnant hypoxia","Anemic hypoxia","Decrease O2 delivery to tissue"],"a":0,"e":"Cyanide poisoning causes histotoxic hypoxia — CO also causes histotoxic hypoxia by binding cytochrome oxidase AND haemoglobin. The key feature is decreased O2 utilisation by tissue despite adequate delivery.<br><br>Take Notes: histotoxic hypoxia → CO + cyanide (↓O2 utilisation) | Stagnant hypoxia → ↓blood flow (heart failure) | Anaemic hypoxia → ↓O2 carrying capacity (anaemia) | Hypoxic hypoxia → ↓O2 availability (altitude, lung disease) | CO/cyanide = histotoxic = tissue cannot use O2."},
/*117*/ {"q":"A person in a marathon race at the end of the race he drinks:","o":["A","Hypertrophic cardiomyopathy","Restrictive cardiomyopathy","Dilation of ventricles"],"a":1,"e":"At the end of a marathon, excessive water consumption (without electrolyte replacement) dilutes plasma sodium, causing exercise-associated hyponatraemia. HCM (hypertrophic cardiomyopathy) is the most common cause of sudden cardiac death in young athletes during exercise.<br><br>Take Notes: HCM → most common cause of sudden cardiac death in young athletes | Marathon + excess water → exercise hyponatraemia | HCM → asymmetric IVS hypertrophy + outflow obstruction | HCM = young athlete SCD = sarcomere mutation."},
/*118*/ {"q":"A patient came in emergency with hypoglycaemic coma. Findings will be there:","o":["Chronic intravascular haemolysis","Profuse Sweating","Hypertension","Bradycardia"],"a":1,"e":"Hypoglycaemic coma produces adrenergic symptoms: profuse sweating (diaphoresis), tachycardia, tremor, pallor, and anxiety (catecholamine release). Sweating is the most characteristic feature differentiating hypoglycaemia from hyperglycaemic states.<br><br>Take Notes: hypoglycaemia → adrenergic symptoms → profuse sweating + tachycardia + tremor + pallor | Neuroglycopaenic symptoms → confusion + seizure + coma | Diaphoresis = key distinguishing feature | Profuse sweating = hypoglycaemia = adrenergic response."},
/*119*/ {"q":"Diagnosis of iron deficiency by which of following:","o":["Serum iron and TIBC","Serum ferritin+Microcytosis","CBC","B (Davidson)"],"a":0,"e":"Iron deficiency is diagnosed by serum iron (low), TIBC (high), and ferritin (low). Serum iron + TIBC together give transferrin saturation (<16% = iron deficient). Ferritin is the most sensitive single test but is an acute phase reactant.<br><br>Take Notes: IDA diagnosis → low serum iron + high TIBC + low ferritin | Transferrin saturation <16% = iron deficient | Ferritin → most sensitive but is acute phase reactant (can be falsely normal in inflammation) | Serum iron + TIBC = the classic IDA diagnostic pair."},
/*120*/ {"q":"Investigation will be confirmatory for anaemia:","o":["Bone marrow biopsy","HbF","HbA2","B (Davidson)"],"a":0,"e":"Bone marrow biopsy (trephine + aspirate) is the definitive/confirmatory investigation for unexplained anaemia, especially to diagnose aplastic anaemia, myelodysplasia, leukaemia, and marrow infiltration. It directly examines marrow cellularity and morphology.<br><br>Take Notes: confirmatory anaemia investigation → bone marrow biopsy (definitive) | HbA2 → confirms beta-thalassaemia trait | Peripheral smear → suggests type | Bone marrow = the gold standard confirmatory anaemia test."},
/*121*/ {"q":"A young female patient with Hb 9.6 g/dl and doctor prescribed iron and after 2 months she presents with iron 8 g/dl and doctor considered for diagnosis?","o":["Retic count","Bone Marrow Biopsy","Hb electrophoresis","Peritin"],"a":1,"e":"A patient whose Hb fails to rise despite adequate iron supplementation for 2 months requires bone marrow biopsy to exclude underlying pathology (thalassaemia, sideroblastic anaemia, marrow infiltration, aplasia). Haemoglobin electrophoresis would also be relevant for thalassaemia.<br><br>Take Notes: Hb not rising after 2 months iron therapy → bone marrow biopsy to exclude underlying pathology | Differential → sideroblastic anaemia + thalassaemia + marrow infiltration | Check → compliance + GI blood loss + malabsorption first | Non-responsive IDA = bone marrow biopsy = the next step."},
/*122*/ {"q":"After how long HBA1C should be repeated to estimate long term control of blood sugar?","o":["2 Months","4 Months","1 Month","3 Months"],"a":3,"e":"HbA1c reflects average blood glucose over the preceding 2-3 months (lifetime of RBC ~120 days). It is therefore repeated every 3 months in diabetic patients to assess glycaemic control and adjust treatment.<br><br>Take Notes: HbA1c → reflects 2-3 months average glucose (RBC lifespan 120 days) | Repeated every 3 months → optimal monitoring interval | Target → <48 mmol/mol (<6.5%) for most diabetics | 3 months = HbA1c = the monitoring interval."},
/*123*/ {"q":"Which bacteria have no cell wall? Mycoplasma. A young man was thrown off motorcycle. A patient came in emergency. Profuse sweating. Diagnosis. A patient came in emergency hypoglycaemia coma. After how long HbA1c. 3 months. A patient came in emergency. Profuse sweating. After trauma. After how long HbA1c is repeated. Succinylcholine is used during anesthesia as skeletal muscle relaxer. In individuals having congenital absence of the following ganglia innervation receive parasympathetic. They gang is complete absence of which of following segment of cord?","o":["S2,3,4","L2-4","S5,S1","Hirschsprung disease"],"a":0,"e":"The parasympathetic innervation of the pelvic organs (bladder, rectum, genitalia) originates from S2-S4 (pelvic splanchnic nerves/nervi erigentes). In Hirschsprung disease, myenteric ganglia are absent from the distal colon (neural crest migration failure).<br><br>Take Notes: pelvic parasympathetic → S2-S4 (pelvic splanchnic/nervi erigentes) | Hirschsprung → absent myenteric ganglia (neural crest failure) | S2-S4 = 'point, shoot, and pee' (erection, ejaculation, micturition) | S2-S4 = pelvic parasympathetics = the sacral parasympathetic origin."},
/*124*/ {"q":"After how long HbA1c is repeated. Succinylcholine. Succinylcholine is used during anesthesia in individuals having congenital absence of ganglia — Hirschsprung. Succinylcholine is used during anaesthesia as skeletal muscle relaxant. relaxant in individuals having prolong anesthesia. congenital absence of following it can cause prolong action in:","o":["4 Months","2 Months","3 Months","Succinylcholine chloride"],"a":2,"e":"Succinylcholine causes prolonged neuromuscular blockade (scoline apnoea) in individuals with pseudocholinesterase deficiency. This genetic variant is detected by the dibucaine number — a reduced inhibition number indicates abnormal pseudocholinesterase.<br><br>Take Notes: succinylcholine prolonged action → pseudocholinesterase deficiency (scoline apnoea) | Normal duration → 3-5 minutes | Pseudocholinesterase deficiency → hours of paralysis | Dibucaine number = pseudocholinesterase test = scoline apnoea screening."},
/*125*/ {"q":"Patient after chemotherapy has nausea and vomiting. Genetic Dr will give?","o":["Plasma cholesterol testers","Plasma 2 lumbricles","Bicep brachii","Metoclopramide"],"a":3,"e":"Chemotherapy-induced nausea and vomiting (CINV) is primarily mediated by serotonin (5-HT3) and substance P (NK1) pathways. First-line treatment is ondansetron (5-HT3 antagonist) + dexamethasone + aprepitant (NK1 antagonist). Metoclopramide (D2 antagonist) is also used as an antiemetic.<br><br>Take Notes: CINV → 5-HT3 (ondansetron) + NK1 (aprepitant) + D2 (metoclopramide) | Ondansetron → most effective for acute CINV | Dexamethasone → enhances antiemetic effect | Metoclopramide = D2 antagonist = CINV antiemetic."},
/*126*/ {"q":"Patient was prescribed captopril with antihypertensive amleolol Now. Complain of cough. What has to be done now?","o":["Ondansetron","Domperidone","Dimethylamine","Loperimide"],"a":3,"e":"ACE inhibitor (captopril) causes a persistent dry cough in 10-15% of patients due to bradykinin accumulation (ACE also degrades bradykinin). The patient should be switched to an ARB (angiotensin receptor blocker, e.g., losartan) which does not cause cough — represented here by loperamide in this source.<br><br>Take Notes: ACE inhibitor cough → bradykinin accumulation | Switch to → ARB (losartan, valsartan) — no cough | ACE inhibitor = captopril, enalapril, ramipril | Captopril cough = bradykinin = switch to ARB."},
/*127*/ {"q":"A 45 years old female is found to have 33 years old female is found to have haematuria and proteinuria. In upper part femoral nerve and artery. Sciatic nerve. Femoral nerve:","o":["Sympathetic system supplies","Adrenal medulla","Preganglionic","Sweet glands"],"a":0,"e":"The sympathetic nervous system supplies sweat glands (eccrine glands) via cholinergic (muscarinic ACh) post-ganglionic fibres — unusually, despite being sympathetic. Sweating is therefore inhibited by anticholinergic drugs.<br><br>Take Notes: sweat glands → sympathetic innervation BUT cholinergic (ACh, not NE) | Blocked by → anticholinergic drugs (atropine) | This is unique among sympathetic effectors | Sympathetic + cholinergic = sweat glands = the exception to the rule."},
/*128*/ {"q":"Patient can't perform supination of arm. Medial meniscus is attached. Medial meniscus. Patient can't perform supination. Association of HLA B.5:","o":["Association of HLA B.5","Ankylosing Spondylitis","Bechet disease","Medial + Radial"],"a":1,"e":"HLA-B27 is associated with ankylosing spondylitis, reactive arthritis, psoriatic arthritis, and IBD-related arthropathy (seronegative spondyloarthropathies). HLA-B5 is associated with Behçet's disease. The question specifically mentions HLA-B5 → Behçet's disease.<br><br>Take Notes: HLA-B27 → ankylosing spondylitis + reactive arthritis + psoriatic arthritis | HLA-B5 (B51) → Behçet's disease | HLA-DR4 → RA + Type 1 DM | HLA-B5 = Behçet's = the HLA association."},
/*129*/ {"q":"U wave in ECG. Which of following raised?","o":["Bradycardia","Hypercalcemia","Hyperkalemia","Hypokalemia"],"a":3,"e":"Prominent U waves on ECG are a classic sign of hypokalaemia. U waves (after the T wave) become prominent when serum K+ falls below 3.5 mmol/L. Severe hypokalaemia also causes ST depression and T wave flattening.<br><br>Take Notes: prominent U waves → hypokalaemia | Also → hypomagnesaemia + digoxin toxicity | Hyperkalaemia → peaked T waves + wide QRS + sine wave | Hypokalaemia = U waves = the ECG electrolyte sign."},
/*130*/ {"q":"Patient having Bleeding diagnosed as VWD. Which test is used for specific VWD diagnosis?","o":["Among the tendency of VWD","Sepal Repolarization","Papillary Muscle Repolarization","Ristocetin test"],"a":3,"e":"The ristocetin agglutination test is the specific diagnostic test for Von Willebrand disease (VWD). Ristocetin promotes VWF-mediated platelet aggregation — absent/reduced aggregation confirms VWD. The ristocetin co-factor activity test quantifies VWF function.<br><br>Take Notes: VWD diagnosis → ristocetin cofactor activity test (specific) | VWD → prolonged BT + prolonged APTT + normal PT | VWF → carrier for Factor VIII + platelet adhesion | Ristocetin test = VWD = the specific diagnostic test."},
/*131*/ {"q":"VWB. Patient presented with low grade fever. ANA. Raised PT. Raised APTT. DIC. Patient presented with low grade fever ANA antibodies, joint. Positive and that was done and RNP was positive. These are seen in?","o":["Decrease PT","Decrease FDP","Increase PT","Increase APTT"],"a":2,"e":"DIC (disseminated intravascular coagulation) causes consumption of all clotting factors, producing elevated PT, elevated APTT, elevated D-dimer/FDP, and thrombocytopaenia with microangiopathic haemolytic anaemia. Raised PT is a hallmark.<br><br>Take Notes: DIC → raised PT + raised APTT + raised D-dimer/FDP + low platelets | Triggers → sepsis + obstetric emergency + malignancy + trauma | D-dimer → most sensitive DIC marker | Raised PT = DIC = factor consumption."},
/*132*/ {"q":"Association of HLA B.5. Association of HLA. Which of following raised in DIC? Ans: A — Increase PT. Association of HLA. These are seen in Mix CT disorder Polymyositis SLE CREST Dermatomyositis:","o":["Mix CT disorders","Polymyositis","SLE","Dermatomyositis"],"a":0,"e":"Mixed connective tissue disease (MCTD) is associated with anti-U1-RNP antibodies (anti-ribonucleoprotein). It combines features of SLE + polymyositis + systemic sclerosis + rheumatoid arthritis, with a relatively good prognosis and Raynaud's phenomenon as a prominent feature.<br><br>Take Notes: anti-U1-RNP → MCTD (Mixed connective tissue disease) | Anti-dsDNA → SLE | Anti-Jo-1 → polymyositis | Anti-Scl-70 → systemic sclerosis | Anti-U1-RNP = MCTD = the overlap syndrome."},
/*133*/ {"q":"Mediator of Deep Sleep?","o":["Serotonin","Norepinephrine","Melatonin","DM"],"a":0,"e":"Serotonin (from the raphe nuclei) is the key mediator of NREM (slow-wave/deep) sleep. Melatonin from the pineal gland promotes sleep onset. Norepinephrine (from locus coeruleus) promotes wakefulness and suppresses REM sleep.<br><br>Take Notes: NREM/deep sleep → serotonin (raphe nuclei) | REM sleep → acetylcholine (pedunculopontine nucleus) | Wakefulness → norepinephrine (locus coeruleus) + histamine | Serotonin = deep sleep = raphe nuclei mediator."},
/*134*/ {"q":"CaCl2 was given to a Rat. Now what will leads to hypercalcaemia. Laboratory increase?","o":["1,25 Dihydroxycholecalciferol","Epinephrine","Cortisol","24,125 Dihydroxycholecalciferol"],"a":0,"e":"Hypercalcaemia from excess CaCl2 would suppress PTH and 1,25-(OH)2 vitamin D production via the calcium-sensing receptor. Exogenous calcium raises serum levels; 1,25-dihydroxycholecalciferol (active Vitamin D) raises calcium by increasing intestinal absorption and is itself elevated in Vitamin D toxicity-induced hypercalcaemia.<br><br>Take Notes: 1,25-(OH)2 vitamin D → increases intestinal Ca absorption + bone resorption | Elevated in → vitamin D toxicity + sarcoidosis + granulomatous disease | PTH → also raises calcium (but via different mechanism) | 1,25-dihydroxycholecalciferol = active Vitamin D = calcium elevation."},
/*135*/ {"q":"Antagonist act on mineralocorticoid excess. PCT. Against aldosterone receptor. Loop of Henle. Against ADH receptor:","o":["Loop of Henle","Against ADH receptor","Against aldosterone receptor","PCT"],"a":1,"e":"ADH receptor antagonists (vaptans — tolvaptan, conivaptan) block V2 receptors in the collecting duct, preventing water reabsorption — producing aquaresis (electrolyte-free water excretion). They are used in SIADH and heart failure with hyponatraemia.<br><br>Take Notes: ADH receptor antagonists → vaptans (tolvaptan, conivaptan) → block V2 receptor in collecting duct | Effect → aquaresis (water-only diuresis) | Used for → SIADH + heart failure hyponatraemia | Anti-ADH receptor = vaptans = aquaresis."},
/*136*/ {"q":"Damage to adductor canal which structure will be spared?","o":["Femoral artery","Femoral vein","Obturator nerve","Saphenous nerve"],"a":2,"e":"The adductor canal (Hunter's canal) contains: femoral artery, femoral vein, saphenous nerve, and nerve to vastus medialis. The obturator nerve passes through the obturator foramen and does NOT pass through the adductor canal — it is therefore spared.<br><br>Take Notes: adductor canal contains → femoral artery + vein + saphenous nerve + nerve to vastus medialis | Obturator nerve → passes through obturator foramen (not adductor canal) | Femoral vessels exit → adductor hiatus into popliteal fossa | Obturator nerve = spared = not in adductor canal."},
/*137*/ {"q":"33 years old female is found to have haematuria and proteinuria. Femoral vein and nerve. In upper part femoral nerve is adductor canal. Adductor canal contains. Which structure in femoral vein and femoral nerve and saphenous nerve. Which structure will be spared?","o":["Adductor nerve","Femoral vein","Saphenous nerve","Obturator nerve"],"a":3,"e":"The obturator nerve is spared in adductor canal injury because it travels through the obturator foramen separately, not through the adductor (subsartorial) canal. The canal contains femoral vessels and the saphenous nerve.<br><br>Take Notes: adductor canal → femoral artery + femoral vein + saphenous nerve | NOT in adductor canal → obturator nerve | Obturator nerve → medial thigh sensation + adductor muscles | Obturator = spared = the nerve not in adductor canal."},
/*138*/ {"q":"Which of following antibody raised in hypersensitivity reaction shrunken — ANA positive:","o":["Type 3","Type 2","Type 1","Type 4"],"a":0,"e":"ANA (antinuclear antibody) positive with immune complex formation = Type III hypersensitivity. ANA is the hallmark of SLE, which is a Type III hypersensitivity disease (immune complex deposition).<br><br>Take Notes: ANA positive → SLE (Type III hypersensitivity) | Type III → immune complex deposition → complement activation | Anti-dsDNA + anti-Smith → specific for SLE | ANA + immune complex = Type III = SLE hypersensitivity."},
/*139*/ {"q":"A(Patau syndrome). Pregnant women having history. MCV > 104. Folic Acid deficiency. Pregnant women MCV > 104 most probable cause. A pregnant woman having history of fast food consumption and raised MCV > 104. The most probable cause:","o":["47+13 (Patau)","47+18 (Edwards)","Trisomy 21","47XY+13 (Patau)"],"a":0,"e":"Patau syndrome (trisomy 13) karyotype is 47,XX/XY+13. Characteristic features: holoprosencephaly, midline cleft lip/palate, polydactyly, cyclopia/microphthalmia, cardiac defects. It is incompatible with prolonged survival (>1 year in <10%).<br><br>Take Notes: Patau syndrome → trisomy 13 (47,+13) | Features → holoprosencephaly + polydactyly + midline defects + cyclopia | Edwards (trisomy 18) → rocker-bottom feet + clenched fists | Patau = 13 = midline defects = polydactyly."},
/*140*/ {"q":"A(Patau syndrome). N-Myc mutation is seen in:","o":["Neuroblastoma","Hypnagogism","Somnambuly","Somnolence"],"a":0,"e":"N-Myc amplification (MYCN) is the hallmark of neuroblastoma — the most common extracranial solid tumour in children. MYCN amplification (>10 copies) indicates aggressive disease with poor prognosis.<br><br>Take Notes: N-Myc (MYCN) amplification → neuroblastoma (poor prognosis) | Neuroblastoma → adrenal medulla or sympathetic ganglia | Markers → elevated urinary catecholamines (VMA, HVA) | MYCN amplification = neuroblastoma = aggressive disease marker."},
/*141*/ {"q":"N-Myc mutation is seen in. Patau syndrome. Fast food MCV>104. A(Patau). N-Myc Neuroblastoma. At Ovulation there is Rupture of Graafian follicle. If pregnant what is leftover corpus luteum?","o":["Nephroblastoma","Neuroblastoma","Retinoblastoma","Wilms Tumor"],"a":1,"e":"Neuroblastoma is associated with N-Myc amplification, arising from adrenal medulla or sympathetic ganglia. After ovulation, if fertilisation occurs, the corpus luteum persists (maintained by hCG) and produces progesterone until the placenta takes over at ~8-10 weeks.<br><br>Take Notes: ovulation → Graafian follicle ruptures → corpus luteum forms | Pregnancy → hCG maintains corpus luteum (progesterone production) | No pregnancy → corpus luteum degenerates → corpus albicans | hCG = corpus luteum maintenance = early pregnancy progesterone."},
/*142*/ {"q":"At Ovulation Graafian follicle rupture. If pregnant. Leftover corpus luteum. N-Myc mutation neuroblastoma. Globlastoma. N-Myc mutation. N-Myc mutation is seen in Neuroblastoma. Glioblastoma. N-Myc mutation is. Patau. Ans: A. N-Myc mutation is seen in:","o":["Glioblastoma","Retinoblastoma","Nephroblastoma","Neuroblastoma"],"a":3,"e":"MYCN (N-Myc) amplification is the key prognostic marker in neuroblastoma. It correlates with rapid progression and resistance to chemotherapy.<br><br>Take Notes: MYCN amplification → neuroblastoma | >10 copies → poor prognosis | Adrenal medulla origin → most common site | N-Myc = MYCN = neuroblastoma = poor prognosis marker."},
/*143*/ {"q":"Patient has cavernous sinus thrombosis. First sign will be? First sign loss of abduction. Patient has cavernous sinus thrombosis. Corpus cavernous sinus thrombosis:","o":["Corpus luteum","Corpus basale","Corpus albicans","Corpus spongiosum"],"a":2,"e":"After the corpus luteum degenerates (in the absence of pregnancy), it is replaced by a white fibrous scar called the corpus albicans. This marks the end of the functional lifespan of the corpus luteum.<br><br>Take Notes: corpus luteum degenerates → corpus albicans (white fibrous scar) | Corpus luteum → maintained by hCG in pregnancy | Corpus albicans = involuted corpus luteum | No pregnancy = corpus luteum → corpus albicans."},
/*144*/ {"q":"Cavernous sinus infection. First sign loss abduction. A patient presenting with first sign cavernous sinus. Loss of abduction of eye. Which nerve? Patient has cavernous sinus. Patient has cavernous sinus thrombosis. Corpus cavernous. Cavernous sinus related to:","o":["Loss of downward and medial rotation","Loss of Abduction","Loss of upward and medial rotation","Loss of eye ball"],"a":1,"e":"CN VI (abducens nerve) is affected first in cavernous sinus thrombosis because it has the longest intracranial course and runs freely within the sinus (not embedded in the lateral wall like CN III, IV, V1, V2). First sign = loss of lateral gaze (abduction) of the ipsilateral eye.<br><br>Take Notes: cavernous sinus thrombosis → CN VI affected first (loss of abduction) | CN III + IV + V1 + V2 → in lateral wall (affected later) | CN VI → runs freely in sinus = most vulnerable | Loss of abduction = CN VI = first cavernous sinus thrombosis sign."},
/*145*/ {"q":"45 year old diabetic patient who is diagnosed since 10 years presented with HTN. Autonomic neuropathy. Pelvic examination. Ans: C. Factor for blood supply to exercising muscle:","o":["Factor for blood supply","Blood supply of exercise muscle","Autonomic neuropathy — diabetic","Decrease parasympathetic activation"],"a":2,"e":"Diabetic autonomic neuropathy affects both sympathetic and parasympathetic fibres. Manifestations include orthostatic hypotension (sympathetic failure), gastroparesis, erectile dysfunction, bladder dysfunction, and resting tachycardia (loss of vagal tone).<br><br>Take Notes: diabetic autonomic neuropathy → sympathetic + parasympathetic dysfunction | Resting tachycardia → loss of vagal tone | Orthostatic hypotension → sympathetic failure | Autonomic neuropathy = diabetic = the multisystem autonomic complication."},
/*146*/ {"q":"Medial meniscus attached to knee through which ligament?","o":["Posterior cruciate","Medial collateral","Anterior cruciate","Lateral collateral"],"a":1,"e":"The medial meniscus is firmly attached to the medial collateral ligament (MCL/tibial collateral ligament) and the joint capsule. This attachment makes it less mobile and more prone to injury with MCL tears — the unhappy triad.<br><br>Take Notes: medial meniscus → attached to MCL (tibial collateral) + joint capsule | Less mobile → more susceptible to injury | Unhappy triad → ACL + MCL + medial meniscus | Lateral meniscus → NOT attached to LCL (more mobile) | MCL = medial meniscus attachment = the immobility cause."},
/*147*/ {"q":"Initiation of Interdigestive myoelectric complexes is done by which hormone?","o":["Motilin","CCK","Gastrin","Secretin"],"a":0,"e":"Motilin is the hormone responsible for initiating the migrating myoelectric complex (MMC) — the interdigestive 'housekeeper' contractions that sweep the gut every ~90 minutes between meals, preventing bacterial overgrowth.<br><br>Take Notes: MMC (migrating myoelectric complex) → motilin (from M cells of small intestine) | Occurs every 90 minutes between meals | Erythromycin → motilin agonist (used as prokinetic) | Motilin = MMC = interdigestive housekeeping contraction."},
/*148*/ {"q":"Accommodation to light reflex remains intact and light reflex is absent:","o":["CCK","Gastrin","Motilin","NO"],"a":3,"e":"Light reflex absent + accommodation reflex intact = Argyll Robertson pupil (neurosyphilis). The pupil accommodates (constricts for near vision) but does NOT react to light — caused by damage to the pretectal nucleus (light reflex pathway) while sparing the Edinger-Westphal nucleus (accommodation pathway).<br><br>Take Notes: Argyll Robertson pupil → accommodates but not to light | Caused by → neurosyphilis (tabes dorsalis) | Pretectal nucleus damaged → light reflex lost | Accommodation intact + light reflex absent = Argyll Robertson = neurosyphilis."},
/*149*/ {"q":"Initiation of interdigestive myoelectric complex done by which hormone? Ans: A — Motilin. Post term pregnancy:","o":["38 weeks","39 weeks","40 weeks completed","42 weeks completed"],"a":3,"e":"Post-term pregnancy is defined as pregnancy ≥42 completed weeks (294 days) from the last menstrual period. WHO recommends induction of labour at 41-42 weeks to prevent complications of placental insufficiency, meconium aspiration, and stillbirth.<br><br>Take Notes: post-term pregnancy → ≥42 completed weeks | Induction recommended → 41-42 weeks (WHO) | Term pregnancy → 37-42 weeks | >42 weeks = post-term = induction threshold."},
/*150*/ {"q":"Initiation of myoelectric complexes. Interdigestive. Post term pregnancy. Post term pregnancy. 42 weeks completed. Which of the following antibody will cross the placenta?","o":["IgM","IgG","IgD","IgA"],"a":1,"e":"IgG is the only immunoglobulin that crosses the placenta via FcRn (neonatal Fc receptor) on syncytiotrophoblasts, providing passive immunity to the foetus and neonate (up to 3-6 months of age).<br><br>Take Notes: placental crossing → IgG only (via FcRn) | IgM → does NOT cross (too large) | Breast milk → IgA (mucosal) | IgG = placental transfer = passive neonatal immunity."},
/*151*/ {"q":"Common to all types of shock is:","o":["Tachycardia","Tissue hypoperfusion","Hypotension","Cold clammy skin"],"a":1,"e":"The common feature of all types of shock (hypovolaemic, cardiogenic, distributive, obstructive) is tissue hypoperfusion — inadequate oxygen delivery to meet metabolic demands. Tachycardia and hypotension are common but not universal (e.g., neurogenic shock can have bradycardia).<br><br>Take Notes: all shock types → tissue hypoperfusion (universal) | Neurogenic shock → bradycardia + hypotension (exception to tachycardia) | Distributive shock → vasodilation | Tissue hypoperfusion = the universal shock definition."},
/*152*/ {"q":"PCV decreases. Volume of blood decreases:","o":["IgA","IgM","IgG","IgD"],"a":2,"e":"IgG is the most abundant serum immunoglobulin (75% of total). It is the only class that crosses the placenta, provides secondary immune response memory, and activates complement via the classical pathway. Decreased PCV (packed cell volume) = anaemia or haemodilution.<br><br>Take Notes: IgG → most abundant serum Ig (75%) | Crosses placenta → neonatal immunity | Secondary immune response → IgG dominant | IgG = most abundant = placenta-crossing immunoglobulin."},
/*153*/ {"q":"A surgeon is performing surgery and a vessel is damaged leading to whole operative field pooled with blood. A vessel is damaged. Most likely damaged is:","o":["Descending Limb","Proximal Convoluted Tubule","Distal Convoluted Tubule","Splenic artery"],"a":3,"e":"The splenic artery is the vessel most commonly damaged causing massive intraoperative haemorrhage during abdominal surgery — it runs along the superior pancreatic border and its tortuous course makes it vulnerable during pancreatic and splenic procedures.<br><br>Take Notes: operative field flooding → splenic artery (tortuous, upper pancreatic border) | Portal vein → posterior pancreatic neck | SMA → mesentery root | Splenic artery = the intraoperative haemorrhage vessel."},
/*154*/ {"q":"Autoimmune disease against single organ:","o":["Sjogren Syndrome","Hashimoto's Thyroiditis","Rheumatoid Arthritis","SLE"],"a":1,"e":"Hashimoto's thyroiditis is an organ-specific autoimmune disease targeting the thyroid gland alone — anti-TPO and anti-thyroglobulin antibodies cause lymphocytic destruction of thyroid follicles, leading to hypothyroidism.<br><br>Take Notes: organ-specific autoimmune → Hashimoto's (thyroid) + Graves + pernicious anaemia + Addison's | Systemic autoimmune → SLE + RA + Sjögren's + scleroderma | Hashimoto's → anti-TPO + anti-thyroglobulin | Single organ = Hashimoto's = the organ-specific autoimmune disease."},
/*155*/ {"q":"Most common cause of negative UTI:","o":["Most common cause of negative","Well behavior","Politeness","Open ended questions"],"a":0,"e":"Culture-negative UTI (sterile pyuria — WBCs in urine without bacterial growth) is most commonly caused by: Chlamydia trachomatis, Mycobacterium tuberculosis, Ureaplasma urealyticum, or partially treated bacterial UTI. Chlamydia requires specific cell culture or NAAT, not standard urine culture.<br><br>Take Notes: sterile pyuria (culture-negative UTI) → Chlamydia + TB + Ureaplasma | Standard culture → misses intracellular/fastidious organisms | NAAT → detects Chlamydia | Sterile pyuria = culture-negative = think Chlamydia or TB."},
/*156*/ {"q":"Which of following is diagnostic test for giant cell arteritis?","o":["ESR","Biopsy","CBC","MRI"],"a":1,"e":"Temporal artery biopsy is the definitive diagnostic test for giant cell arteritis (GCA/temporal arteritis) — it shows granulomatous inflammation with giant cells in the vessel wall. ESR is elevated but not diagnostic; biopsy confirms.<br><br>Take Notes: giant cell arteritis diagnosis → temporal artery biopsy (gold standard) | ESR → usually >50 mm/hr (sensitive but not specific) | Start steroids immediately → before biopsy if vision threatened | Temporal artery biopsy = GCA = the definitive diagnostic test."},
/*157*/ {"q":"In toxoplasmosis antibody which will be raised?","o":["IgG","IgD","IgM","IgA"],"a":0,"e":"In acute toxoplasmosis, IgM antibodies rise first (within 1-2 weeks), followed by IgG (persists for life). For congenital toxoplasmosis screening, IgM in the neonate is diagnostic (IgG crosses placenta and reflects maternal status). In adults, IgG avidity testing distinguishes recent from past infection.<br><br>Take Notes: acute toxoplasmosis → IgM rises first (acute marker) | IgG → persists for life (past infection) | Congenital toxo → neonatal IgM (diagnostic) | IgG = the persistent marker = used for population serology."},
/*158*/ {"q":"Autoimmune disease. Against single organ. Hashimoto thyroiditis. Single organ. Autoimmune. Ans: B. A patient got injury on medial side of knee. There is loss of sensation on medial side of leg. Endoderm of 3rd pharyngeal pouch. Which of the following is autoimmune disease?","o":["Sjogren Syndrome","SLE","Rheumatoid Arthritis","Hashimoto's Thyroiditis"],"a":3,"e":"Hashimoto's thyroiditis is classified as an organ-specific autoimmune disease (targets thyroid only). SLE and RA are systemic autoimmune diseases. Sjögren's primarily targets exocrine glands.<br><br>Take Notes: organ-specific autoimmune → Hashimoto's + Graves + Addison's | Systemic → SLE + RA + Sjögren's + scleroderma | Hashimoto's → anti-TPO antibodies + lymphocytic thyroiditis | Hashimoto's = organ-specific autoimmune = thyroid only."},
/*159*/ {"q":"Which type of necrosis is as a result of MI:","o":["MI","Casseous necrosis","Liquefactive necrosis","Coagulative necrosis"],"a":3,"e":"Myocardial infarction causes coagulative necrosis — ischaemia denatures structural proteins while preserving cell outlines (ghost cells) for 12-24 hours. This is the characteristic necrosis type in all solid organ ischaemia.<br><br>Take Notes: MI necrosis → coagulative (ghost cells preserved, ischaemia) | Brain infarction → liquefactive (enzyme-rich neurons autolyse) | TB → caseous necrosis (cheese-like) | Pancreatitis → fat necrosis | Coagulative = MI = solid organ ischaemia."},
/*160*/ {"q":"A nutritionist patient presented hypertensive. Which following should not give her diet plan to come:","o":["Egg white part","Mucosa","Lamina Propria","Dates"],"a":3,"e":"Dates have a high glycaemic index and high potassium content — for a hypertensive patient on a dietary plan, potassium-rich foods are generally beneficial (reduces BP) but in patients with renal impairment or on ACE inhibitors/ARBs, high potassium intake may be restricted. Dates should be limited due to high sugar content.<br><br>Take Notes: hypertensive diet → reduce Na+ + reduce saturated fat + increase K+ (fruits/vegetables) | Dates → high GI + high K+ (problematic in renal impairment) | Nutritionist caution → dates restricted in diabetic hypertension | Dates = high GI + high K+ = restricted for hypertensive diabetic patient."}
];
